/**
 * 扩展按钮控件
 * 提供带有悬停效果和点击状态的按钮组件
 */
'use strict';

/**
 * 扩展按钮构造函数
 * @param {Object} config - 配置对象
 * @param {HTMLElement} config.parentDiv - 父容器元素
 * @param {number} config.width - 按钮宽度
 * @param {number} config.height - 按钮高度
 * @param {string} [config.backgroundColor] - 背景颜色
 * @param {string} [config.backgroundImage] - 背景图片URL
 * @param {boolean} [config.isThreeStatus] - 是否启用三态模式
 * @param {boolean} [config.floatRightUp] - 是否浮动到右上角
 * @param {boolean} [config.floatRightBottom] - 是否浮动到右下角
 * @param {Function} config.onclick - 点击回调函数
 */
function MyButtonEx(config) {
    var containerDiv = document.createElement("div");
    containerDiv.style.width = config.width + "px";
    containerDiv.style.height = config.height + "px";

    if (config.floatRightUp) {
        containerDiv.style.position = "absolute";
        containerDiv.style.right = "0px";
        containerDiv.style.top = "0px";
    } else if (config.floatRightBottom) {
        containerDiv.style.position = "absolute";
        containerDiv.style.right = "0px";
        containerDiv.style.bottom = "0px";
    }
    config.parentDiv.appendChild(containerDiv);

    var canvas = document.createElement("canvas");
    canvas.setAttribute("width", config.width + "px");
    canvas.setAttribute("height", config.height + "px");
    canvas.style.width = config.width + "px";
    canvas.style.height = config.height + "px";
    containerDiv.appendChild(canvas);
    var ctx = canvas.getContext("2d", { willReadFrequently: false });

    var image, normalImageData, hoverImageData, activeImageData;
    var isChecked = false;

    /**
     * 获取按钮是否被选中
     * @returns {boolean} 是否选中
     */
    this.getIsChecked = function () {
        return isChecked;
    };

    /**
     * 获取按钮元素
     * @returns {HTMLElement} 按钮容器元素
     */
    this.getEl = function () {
        return containerDiv;
    };

    if (config.backgroundImage) {
        image = new Image();
        image.onload = function () {
            drawNormal();
            normalImageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            hoverImageData = Comman.getBrightnessImageData(ctx, canvas, 1.2);
            if (config.isThreeStatus) {
                activeImageData = Comman.getBrightnessImageData(ctx, canvas, 1.5);
            }
        };
        image.src = config.backgroundImage;
    } else {
        ctx.fillStyle = config.backgroundColor || 'rgb(169, 169, 169)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        normalImageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        hoverImageData = Comman.getBrightnessImageData(ctx, canvas, 1.2);
        if (config.isThreeStatus) {
            activeImageData = Comman.getBrightnessImageData(ctx, canvas, 1.5);
        }
    }

    containerDiv.onmouseover = function () {
        if (!config.isThreeStatus || (config.isThreeStatus && !isChecked)) {
            drawHover();
        }
    };

    containerDiv.onmouseout = function () {
        if (!config.isThreeStatus || (config.isThreeStatus && !isChecked)) {
            drawNormalFromData();
        }
    };

    /**
     * 绘制正常状态（使用图片）
     */
    function drawNormal() {
        ctx.drawImage(image, 0, 0, config.width, config.height);
    }

    /**
     * 绘制正常状态（使用缓存数据）
     */
    function drawNormalFromData() {
        if (normalImageData) {
            ctx.putImageData(normalImageData, 0, 0);
        }
    }

    /**
     * 绘制悬停状态
     */
    function drawHover() {
        if (hoverImageData) {
            ctx.putImageData(hoverImageData, 0, 0);
        }
    }

    /**
     * 绘制激活状态
     */
    function drawActive() {
        if (activeImageData) {
            ctx.putImageData(activeImageData, 0, 0);
        }
    }

    containerDiv.onclick = function (e) {
        e.preventDefault();
        e.stopPropagation();
        if (config.isThreeStatus) {
            if (!isChecked) {
                isChecked = true;
                drawActive();
            } else {
                isChecked = false;
                drawNormalFromData();
            }
        }
        config.onclick();
    };
}

'use strict';

/**
 * @fileoverview 消息提示控件模块，提供滑动动画效果的消息提示
 * @module MyMsgEx
 */

/**
 * 消息提示类
 * @class
 * @param {Object} config - 配置对象
 * @param {HTMLElement} config.slidingDiv - 滑动的div元素
 * @param {number} config.distanceX - X方向移动距离
 * @param {number} config.distanceY - Y方向移动距离
 * @param {number} config.duration - 动画持续时间（毫秒）
 */
function MyMsgEx(config) {
    var slidingDiv = config.slidingDiv;
    var startX = Number(slidingDiv.style.left.replace("px", ""));
    var startY = Number(slidingDiv.style.top.replace("px", ""));
    var endX = startX + config.distanceX; // 目标X坐标  
    var endY = startY - config.distanceY; // 目标Y坐标  

    // 定义滑动动画的持续时间（以毫秒为单位）  
    var duration = config.duration;

    function setMsg(s) {
        slidingDiv.innerHTML = s;
    }

    function slideOut() {
        // 计算每一帧需要移动的距离（假设每秒60帧）  
        var frames = duration / (1000 / 60);
        var deltaX = (endX - startX) / frames;
        var deltaY = (endY - startY) / frames;

        var frameCount = 0;

        // 使用requestAnimationFrame来执行动画  
        function animate() {
            if (frameCount < frames) {
                slidingDiv.style.left = (endX - frameCount * deltaX) + 'px';
                slidingDiv.style.top = (endY - frameCount * deltaY) + 'px';

                frameCount++;

                // 请求下一帧  
                requestAnimationFrame(animate);
            }
            else {
                slidingDiv.style.display = "none";
            }
        }

        // 开始动画  
        requestAnimationFrame(animate);
    }

    function slideIn() {
        slidingDiv.style.display = "";
        // 计算每一帧需要移动的距离（假设每秒60帧）  
        var frames = duration / (1000 / 60);
        var deltaX = (endX - startX) / frames;
        var deltaY = (endY - startY) / frames;

        var frameCount = 0;
        var startTime = new Date();

        // 使用requestAnimationFrame来执行动画  
        function animate() {
            if (frameCount < frames) {
                slidingDiv.style.left = (startX + frameCount * deltaX) + 'px';
                slidingDiv.style.top = (startY + frameCount * deltaY) + 'px';

                frameCount++;

                // 请求下一帧  
                requestAnimationFrame(animate);
            }
            else if (new Date() - startTime < duration + 3000) {
                // 请求下一帧  
                requestAnimationFrame(animate);
            }
            else {
                slideOut();
            }
        }

        // 开始动画  
        requestAnimationFrame(animate);
    }

    return {
        slideIn: slideIn,
        slideOut: slideOut,
        setMsg: setMsg
    }
}
'use strict';

/**
 * @fileoverview 消息提示控件2模块，提供窗口形式的消息提示
 * @module MyMsgEx2
 */

/**
 * 消息提示2类
 * @class
 * @param {Object} config - 配置对象
 * @param {string} config.parentId - 父元素ID
 * @param {HTMLElement} config.parentDiv - 父容器元素
 */
function MyMsgEx2(config) {
    var myWindowConfig = {
        id: "myMsgEx2_" + config.parentId,
        parent: config.parentDiv,
        width: 250,
        height: 100,
        topBorderHeight: 7,
        bottomBorderHeight: 15,
        leftBorderWidth: 10,
        rightBorderWidth: 12,       
        backgroundImage: getLocation() + "/images/FormulaTool/formulaCondition.png",
        isDrag: true
    };

    var outerWindow;
    var o = windowExManager.find(myWindowConfig.id);
    if (!o) {
        outerWindow = new MyWindowEx(myWindowConfig);
    }
    else {
        outerWindow = o.win;
    }
    outerWindow.setZIndex(10000000);
    outerWindow.hide();
    var mainDivWidth = myWindowConfig.width - myWindowConfig.leftBorderWidth - myWindowConfig.rightBorderWidth;
    var mainDivHeight = myWindowConfig.height - myWindowConfig.topBorderHeight - myWindowConfig.bottomBorderHeight;
    var titleDivHeight = 20;
    var buttonDivHeight = 20;
    var middleDivHeight = mainDivHeight - titleDivHeight - buttonDivHeight;
    var mainDiv = document.createElement("div");
    mainDiv.style.width = mainDivWidth + "px";
    mainDiv.style.height = mainDivHeight + "px";
    outerWindow.setWindowContent(mainDiv);

    var titleDiv = document.createElement("div");
    titleDiv.style.width = mainDivWidth + "px";
    titleDiv.style.height = titleDivHeight + "px";
    mainDiv.appendChild(titleDiv);

    var middleDiv = document.createElement("div");
    middleDiv.style.width = mainDivWidth + "px";
    middleDiv.style.height = middleDivHeight + "px";
    middleDiv.style.textAlign = "center";
    middleDiv.style.fontSize = "10pt";
    mainDiv.appendChild(middleDiv);

    var buttonDiv = document.createElement("div");
    buttonDiv.style.width = mainDivWidth + "px";
    buttonDiv.style.height = buttonDivHeight + "px";
    buttonDiv.style.position = "absolute";
    buttonDiv.style.left = "0px";
    buttonDiv.style.bottom = "0px";    
    mainDiv.appendChild(buttonDiv);

    setupConfirmButton();

    function setupConfirmButton() {
        var buttonConfig = {
            parentDiv: buttonDiv,
            backgroundColor: "#CAFFFF",
            width: 40,
            height: 20,
            onclick: function () {
                close();
            }
        };
        var o = new MyButtonEx(buttonConfig);
        var t1 = o.getEl();
        t1.style.position = "absolute";
        t1.style.left = (mainDivWidth - 40) / 2 + "px";
        t1.style.top = (buttonDivHeight - 20) / 2 + "px";
        t1.style.fontSize = "10pt";
        t1.style.color = "red";
        t1.style.border = "1px solid #CAFFFF";
        t1.innerText = "确定";
    }

    function close() {
        outerWindow.hide();
    }

    function showMsg(title, s, paddingTop) {
        titleDiv.innerHTML = title;
        middleDiv.innerHTML = s;
        middleDiv.style.paddingTop = paddingTop;
        outerWindow.show();
    }

    return {
        showMsg: showMsg
    }
}
'use strict';

/**
 * @fileoverview 垂直标签页控件模块，提供垂直布局的标签页组件
 * @module MyTabVerticalEx
 */

/**
 * 垂直标签页类
 * @class
 * @param {Object} config - 配置对象
 * @param {Array} config.tabs - 标签页配置数组
 * @param {Object} myWindowConfig - 窗口配置对象
 */
function MyTabVerticalEx(config, myWindowConfig) {
    var mainDiv, selectedTab;    
    var tabsAr = [];    

    doJob();
    function doJob() {
        var t = document.getElementById(myWindowConfig.id);
        if (t) {
            t.parentElement.removeChild(t);
        }        
        var myWindow = new MyWindowEx(myWindowConfig);

        mainDiv = document.createElement("div");
        mainDiv.style.width = "100%";
        mainDiv.style.height = "100%";
        mainDiv.style.margin = "0px";
        mainDiv.style.padding = "0px";
        mainDiv.style.textAlign = "center";
        myWindow.setWindowContent(mainDiv);

        setTabs();
    }

    function setTabs() {
        var tAr = config.tabs;
        for (var i = 0; i < tAr.length; i++) {
            var t = tAr[i];
            var t1 = new OneTab(t);
            tabsAr.push(t1);
        }        
    }

    function OneTab(t) {
        let me = this;
        this.id = t.id;
        this.hint = t.hint;
        var t1 = document.createElement("div");
        t1.style.width = t.width + "px";
        t1.style.height = t.height + "px";
        t1.style.marginTop = (t.marginTop + "px") || "0px";
        t1.style.position = "relative";
        mainDiv.appendChild(t1);

        var canvas = document.createElement("canvas");
        canvas.setAttribute("width", t.width + "px");
        canvas.setAttribute("height", t.height + "px");
        canvas.style.width = t.width + "px";
        canvas.style.height = t.height + "px";
        t1.appendChild(canvas);

        var t2;

        this.drawHint = function () {
            t2 = document.createElement("div");
            var hintWidth = 100;
            t2.style.width = hintWidth + "px";
            t2.style.height = t.height + "px";
            t2.style.position = "absolute";
            t2.style.top = "0px";
            t2.style.left = (- hintWidth) + "px";
            t2.style.backgroundColor = "#EDF2FA";
            t2.style.textAlign = "center";
            t2.style.color = "red";
            t2.style.display = "none";
            t2.innerHTML = this.hint;
            t1.appendChild(t2);
            return t2;
        }

        if (this.hint) {
            this.hintEl = this.drawHint();
        }

        var ctx = canvas.getContext("2d", { willReadFrequently: false });

        var imageData2;
        var imageData3;

        if (t.backgroundImage) {
            var image = new Image();
            image.onload = function () {
                doJob();
            }
            image.src = t.backgroundImage;
        }
        else {
            doJob();
        }

        function doJob() {
            draw1();
            imageData2 = Comman.getBrightnessImageData(ctx, canvas, 1.2);
            imageData3 = Comman.getBrightnessImageData(ctx, canvas, 1.5);
            t1.onmouseover = function () {
                if (!isSelected()) {
                    draw2();
                }
                showHint();
            }
            t1.onmouseout = function () {
                if (!isSelected()) {
                    draw1();
                }
                hideHint();
            }
        }

        function showHint() {
            if (t2)
                t2.style.display = "";
        }

        function hideHint() {
            if (t2)
                t2.style.display = "none";
        }

        function draw1() {
            if (t.backgroundImage)
                ctx.drawImage(image, 0, 0);
            else {
                ctx.fillStyle = t.backgroundColor || 'rgb(169, 169, 169)'; // 或者使用十六进制 '#a9a9a9'  
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            }
        }

        function draw2() {
            ctx.putImageData(imageData2, 0, 0);
        }

        function draw3() {
            ctx.putImageData(imageData3, 0, 0);
        }

        t1.onclick = function () {
            if (!isSelected()) {
                selectedTab && selectedTab.unMarkTabSelected();
                me.markTabSelected();
            }
            selectedTab = me;
            me.onClickDo();
        }

        this.onClickDo = function () {
            if (!t.onclick) {
                return;
            }
            t.onclick(me);
        }

        function isSelected() {
            if (!selectedTab)
                return false;
            return selectedTab.id == me.id;
        }

        this.unMarkTabSelected = function () {
            draw1();
        }

        this.markTabSelected = function () {
            draw3();
        }
    }

    this.hide = function () {
        mainDiv.style.display = "none";
    }

    this.show = function () {
        mainDiv.style.display = "";
    }

    this.updateHint = function (id, s) {        
        var o = tabsAr.Find(function (p) { return p.id == id; });
        if (o == null) {
            return;
        }
        o.hint = s;
        if (o.hintEl) {
            o.hintEl.innerHTML = s;
        }
        else {
            o.hintEl = o.drawHint();
        }
    }
}

/**
 * 自定义窗口控件
 * 提供可拖动、可关闭的窗口组件
 */
"use strict";

/**
 * 自定义窗口构造函数
 * @param {Object} config - 配置对象
 * @param {string} config.id - 窗口ID
 * @param {HTMLElement} config.parent - 父容器元素
 * @param {number} config.width - 窗口宽度
 * @param {number} config.height - 窗口高度
 * @param {string} config.title - 窗口标题
 * @param {boolean} [config.isDrag] - 是否可拖动
 * @param {string} [config.align] - 对齐方式
 */
function MyWindow(config) {
    var mainDiv, titleDiv, middleDiv;

    doJob();

    /**
     * 设置窗口内容
     * @param {HTMLElement} content - 内容元素
     */
    this.setWindowContent = function (content) {
        middleDiv.innerHTML = "";
        middleDiv.appendChild(content);
    };

    /**
     * 显示窗口
     */
    this.show = function () {
        mainDiv.style.display = "";
    };

    /**
     * 关闭窗口
     */
    this.close = function () {
        mainDiv.parentElement.removeChild(mainDiv);
    };

    /**
     * 初始化窗口
     */
    function doJob() {
        mainDiv = document.createElement("div");
        mainDiv.setAttribute("id", config.id);
        setMainDivProps();

        titleDiv = document.createElement("div");
        titleDiv.style.width = "100%";
        titleDiv.style.height = "32px";
        titleDiv.style.lineHeight = "32px";
        titleDiv.style.backgroundColor = "#F8FAFC";
        titleDiv.style.display = "flex";
        titleDiv.style.alignItems = "center";
        titleDiv.style.borderTopLeftRadius = "4px";
        titleDiv.style.borderTopRightRadius = "4px";
        titleDiv.style.border = "1px solid #E2E8F0";
        titleDiv.style.borderBottom = "none";
        setTitleIcon();
        setTitle();
        setCloseButton();
        mainDiv.appendChild(titleDiv);

        middleDiv = document.createElement("div");
        setMiddleDivProps();
        mainDiv.appendChild(middleDiv);

        config.parent.appendChild(mainDiv);

        if (config.isDrag) {
            new Drag3(titleDiv, mainDiv, config.parent);
        }
    }

    /**
     * 设置关闭按钮
     */
    function setCloseButton() {
        var closeButton = document.createElement('div');
        closeButton.style.cursor = 'pointer';
        closeButton.style.width = '32px';
        closeButton.style.height = '32px';
        closeButton.style.display = 'flex';
        closeButton.style.alignItems = 'center';
        closeButton.style.justifyContent = 'center';
        closeButton.style.color = '#4A5568';
        closeButton.style.fontSize = '14px';
        closeButton.style.fontWeight = 'bold';
        closeButton.style.transition = 'background-color 0.2s ease';
        closeButton.innerHTML = '×';
        closeButton.onmouseover = function() {
            closeButton.style.backgroundColor = '#E2E8F0';
        };
        closeButton.onmouseout = function() {
            closeButton.style.backgroundColor = 'transparent';
        };
        titleDiv.appendChild(closeButton);
        closeButton.onclick = function (e) {
            mainDiv.parentElement.removeChild(mainDiv);
        };
    }

    /**
     * 设置标题
     */
    function setTitle() {
        var titleElement = document.createElement('div');
        titleElement.style.flex = '1';
        titleElement.style.height = '32px';
        titleElement.style.lineHeight = '32px';
        titleElement.style.fontSize = '10pt';
        titleElement.style.fontWeight = '500';
        titleElement.style.color = "#2D3748";
        titleElement.innerText = config.title;
        titleDiv.appendChild(titleElement);
    }

    /**
     * 设置标题图标
     */
    function setTitleIcon() {
        var iconElement = document.createElement('div');
        iconElement.style.width = '16px';
        iconElement.style.height = '16px';
        iconElement.style.marginLeft = '12px';
        iconElement.style.marginRight = '8px';
        iconElement.style.overflow = 'hidden';
        iconElement.style.background = 'url("data:image/gif;base64,R0lGODlhDQANAKIAAAAAAP///1CByW2d153K7f///wAAAAAAACH5BAEAAAUALAAAAAANAA0AAAMkKLrM9DCSRlm4OAcVhh/dtwlayX0gOpbaKaoci7leWMfyWDUJADs=") no-repeat center center';
        titleDiv.appendChild(iconElement);
    }

    /**
     * 设置中间内容区域属性
     */
    function setMiddleDivProps() {
        middleDiv.style.width = "100%";
        middleDiv.style.height = "calc(100% - 32px)";
        middleDiv.style.padding = "1px";
        middleDiv.style.boxSizing = "border-box";
    }

    /**
     * 设置主容器属性
     */
    function setMainDivProps() {
        mainDiv.style.width = config.width + "px";
        //mainDiv.style.height = config.height + "px";
        mainDiv.style.margin = "0px";
        mainDiv.style.padding = "0px";
        mainDiv.style.backgroundColor = "#fff";
        mainDiv.style.border = "1px solid #E2E8F0";
        mainDiv.style.borderRadius = "4px";
        mainDiv.style.boxShadow = "0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)";
        mainDiv.style.zIndex = 99999;
        mainDiv.style.overflow = "hidden";

        var parentWidth = config.parent.clientWidth;
        var parentHeight = config.parent.clientHeight;

        if (config.align == "center-top") {
            mainDiv.style.position = "absolute";
            mainDiv.style.left = (parentWidth - config.width) / 2 + "px";
        } else {
            mainDiv.style.position = "absolute";
            mainDiv.style.left = (parentWidth - config.width) / 2 + "px";
            mainDiv.style.top = (parentHeight - config.height) / 2 + "px";
        }
    }
}
"use strict";

/**
 * @fileoverview 扩展窗口控件模块，提供带有背景图片的可拖动窗口组件
 * @module MyWindowEx
 */

/**
 * 窗口管理器类
 * @class
 */
function WindowExManager() {
  /**
   * 窗口数组
   * @type {Array}
   */
  let winAr = [];

  /**
   * 添加窗口
   * @function add
   * @param {Object} o - 窗口对象
   */
  this.add = function (o) {
    winAr.push(o);
  };

  this.find = function (id) {
    for (var i = 0; i < winAr.length; i++) {
      if (winAr[i].id == id) {
        return winAr[i];
      }
    }
    return null;
  };
}

let windowExManager = new WindowExManager();

function MyWindowEx(config) {
  let me = this;
  let mainDiv, middleDiv;
  var middleDivWidth;
  var middleDivHeight;
  let backgroundCanvas, backgroundCtx, bgImage, middleWidth, middleHeight;

  doJob();

  windowExManager.add({
    id: config.id,
    win: me,
  });

  this.setWindowContent = function (t) {
    middleDiv.innerHTML = "";
    middleDiv.appendChild(t);
  };

  this.adjustSize = function (w, h) {
    if (w != -1) {
      var deltaWidth = w - middleDivWidth;
      config.width += deltaWidth;
    }

    if (h != -1) {
      var deltaHeight = h - middleDivHeight;
      config.height += deltaHeight;
    }

    resize();
  };

  this.show = function () {
    mainDiv.style.display = "";
  };

  this.hide = function () {
    mainDiv.style.display = "none";
  };

  this.setZIndex = function (v) {
    mainDiv.style.zIndex = v;
  };

  function resize() {
    setMainDivProps();
    setMiddleDivProps();
    setBackgroundCanvasProps();
    drawBackgroundImageDo();
  }

  function doJob() {
    mainDiv = document.createElement("div");
    mainDiv.setAttribute("id", config.id);
    setMainDivProps();

    middleDiv = document.createElement("div");
    setMiddleDivProps();
    mainDiv.appendChild(middleDiv);

    if (config.backgroundImage) drawBackgroundImage();

    if (config.closeButtonConfig) setColseButtonDiv();

    config.parent.appendChild(mainDiv);

    if (config.isDrag) new Drag(mainDiv, config.parent);
  }

  function setMiddleDivProps() {
    middleDivWidth =
      config.width - config.leftBorderWidth - config.rightBorderWidth;
    middleDivHeight =
      config.height - config.topBorderHeight - config.bottomBorderHeight;
    middleDiv.style.position = "absolute";
    middleDiv.style.left = config.leftBorderWidth + "px";
    middleDiv.style.top = config.topBorderHeight + "px";
    middleDiv.style.right = config.rightBorderWidth + "px";
    middleDiv.style.bottom = config.bottomBorderHeight + "px";
  }

  function setMainDivProps() {
    mainDiv.style.width = config.width + "px";
    mainDiv.style.height = config.height + "px";
    mainDiv.style.margin = "0px";
    mainDiv.style.padding = "0px";
    if (config.backgroundColor)
      mainDiv.style.backgroundColor = config.backgroundColor;
    mainDiv.style.boxShadow = "5px 5px 10px rgba(0, 0, 0, 0.2)";
    mainDiv.style.borderRadius = "10px";
    var w = Number(config.parent.style.width.replace("px", ""));
    var h = Number(config.parent.style.height.replace("px", ""));
    if (config.align == "center-top") {
      mainDiv.style.position = "absolute";
      mainDiv.style.left = (w - config.width) / 2 + "px";
    } else {
      mainDiv.style.position = "absolute";
      mainDiv.style.left = (w - config.width) / 2 + "px";
      mainDiv.style.top = (h - config.height) / 2 + "px";
    }
  }

  function setBackgroundCanvasProps() {
    backgroundCanvas.style.width = config.width + "px";
    backgroundCanvas.style.height = config.height + "px";
    backgroundCanvas.setAttribute("width", config.width + "px");
    backgroundCanvas.setAttribute("height", config.height + "px");
  }

  function drawBackgroundImage() {
    var width, height;

    backgroundCanvas = document.createElement("canvas");
    setBackgroundCanvasProps();
    backgroundCtx = backgroundCanvas.getContext("2d", {
      willReadFrequently: false,
    });
    mainDiv.appendChild(backgroundCanvas);

    bgImage = new Image();
    bgImage.onload = function () {
      width = bgImage.width;
      height = bgImage.height;
      middleWidth = width - config.leftBorderWidth - config.rightBorderWidth;
      middleHeight =
        height - config.topBorderHeight - config.bottomBorderHeight;
      drawBackgroundImageDo();
    };
    bgImage.src = config.backgroundImage;
  }

  function drawBackgroundImageDo() {
    backgroundCtx.clearRect(0, 0, backgroundCtx.width, backgroundCtx.height);
    draw1();
    draw2();
    draw3();
    draw4();
    draw5();
    draw6();
    draw7();
    draw8();
    draw9();
  }

  function draw1() {
    backgroundCtx.drawImage(
      bgImage,
      0,
      0,
      config.leftBorderWidth,
      config.topBorderHeight,
      0,
      0,
      config.leftBorderWidth,
      config.topBorderHeight
    );
  }

  function draw2() {
    backgroundCtx.drawImage(
      bgImage,
      config.leftBorderWidth,
      0,
      middleWidth,
      config.topBorderHeight,
      config.leftBorderWidth,
      0,
      middleDivWidth,
      config.topBorderHeight
    );
  }

  function draw3() {
    backgroundCtx.drawImage(
      bgImage,
      config.leftBorderWidth + middleWidth,
      0,
      config.rightBorderWidth,
      config.topBorderHeight,
      config.leftBorderWidth + middleDivWidth,
      0,
      config.rightBorderWidth,
      config.topBorderHeight
    );
  }

  function draw4() {
    backgroundCtx.drawImage(
      bgImage,
      0,
      config.topBorderHeight,
      config.leftBorderWidth,
      middleHeight,
      0,
      config.topBorderHeight,
      config.leftBorderWidth,
      middleDivHeight
    );
  }

  function draw5() {
    backgroundCtx.drawImage(
      bgImage,
      config.leftBorderWidth,
      config.topBorderHeight,
      middleWidth,
      middleHeight,
      config.leftBorderWidth,
      config.topBorderHeight,
      middleDivWidth,
      middleDivHeight
    );
  }

  function draw6() {
    backgroundCtx.drawImage(
      bgImage,
      config.leftBorderWidth + middleWidth,
      config.topBorderHeight,
      config.rightBorderWidth,
      middleHeight,
      config.leftBorderWidth + middleDivWidth,
      config.topBorderHeight,
      config.rightBorderWidth,
      middleDivHeight
    );
  }

  function draw7() {
    backgroundCtx.drawImage(
      bgImage,
      0,
      config.topBorderHeight + middleHeight,
      config.leftBorderWidth,
      config.bottomBorderHeight,
      0,
      config.topBorderHeight + middleDivHeight,
      config.leftBorderWidth,
      config.bottomBorderHeight
    );
  }

  function draw8() {
    backgroundCtx.drawImage(
      bgImage,
      config.leftBorderWidth,
      config.topBorderHeight + middleHeight,
      middleWidth,
      config.bottomBorderHeight,
      config.leftBorderWidth,
      config.topBorderHeight + middleDivHeight,
      middleDivWidth,
      config.bottomBorderHeight
    );
  }

  function draw9() {
    backgroundCtx.drawImage(
      bgImage,
      config.leftBorderWidth + middleWidth,
      config.topBorderHeight + middleHeight,
      config.rightBorderWidth,
      config.bottomBorderHeight,
      config.leftBorderWidth + middleDivWidth,
      config.topBorderHeight + middleDivHeight,
      config.rightBorderWidth,
      config.bottomBorderHeight
    );
  }

  function setColseButtonDiv() {
    config.closeButtonConfig.parentDiv = mainDiv;
    config.closeButtonConfig.floatRightUp = true;
    let t = config.closeButtonConfig.onclick;
    config.closeButtonConfig.onclick = function () {
      if (t) {
        t();
      }
      mainDiv.style.display = "none";
    };
    new MyButtonEx(config.closeButtonConfig);
  }
}

"use strict";

/**
 * @fileoverview 左侧标签操作模块，提供行选择高亮功能
 * @module OperLeftLabel
 */

/**
 * 左侧标签鼠标是否按下
 * @type {boolean}
 */
let leftLabelIsMouseDown = false;

/**
 * 左侧标签鼠标移动行标记
 * @type {Array}
 */
let leftLabelMousemoveRowMarks = [];

/**
 * 左侧标签选择起始行
 * @type {number}
 */
let leftLabelSelectStartRow = -1;

/**
 * 左侧标签选择结束行
 * @type {number}
 */
let leftLabelSelectEndRow = -1;

/**
 * 左侧标签已绘制标记
 * @type {Array}
 */
let leftLabelHaveDrawMarks = [];

/**
 * 取消高亮左侧标签
 * @function unHilightLeftLabel
 * @param {Array} labelDivs - 标签div数组
 * @param {Array} splitorDivs - 分隔线div数组
 * @param {number} startrow - 起始行
 * @param {number} endRow - 结束行
 */
function unHilightLeftLabel(labelDivs, splitorDivs, startrow, endRow) {
  for (var i = 0; i < labelDivs.length; i++) {
    if (
      leftLabelHaveDrawMarks.indexOf(i) != -1 ||
      (i >= startrow && i <= endRow)
    ) {
      var t = labelDivs[i].div;
      t.style.backgroundColor = "#ffffff";
      var tt1 = splitorDivs[i];
      var tt2 = tt1.div.querySelector("div");
      tt2.style.backgroundColor = "#DBDBDB";

      var tt3 = t.querySelector(".leftLabelHilight");
      if (tt3) {
        tt3.parentElement.removeChild(tt3);
      }
    }
  }
}

function showHilightLeftLabelOne(labelDivs, splitorDivs, row) {
  var t1 = labelDivs[row];
  var t = t1.div;
  t.style.backgroundColor = "rgba(242, 242, 242, 1)";
  var tt1 = splitorDivs[row];
  var tt2 = tt1.div.querySelector("div");
  tt2.style.backgroundColor = "white";

  var tt3 = t.querySelector(".leftLabelHilight");
  if (!tt3) {
    tt3 = document.createElement("div");
    tt3.style.position = "absolute";
    tt3.style.top = "0px";
    tt3.style.right = "0px";
    tt3.style.height = "100%";
    tt3.style.width = "2px";
    tt3.style.backgroundColor = theme.hilightColor;
    tt3.setAttribute("class", "leftLabelHilight");
    t.appendChild(tt3);
  }
}

function OperLeftLabel(operItem, row, labelDivs, splitorDivs, parentObj) {
  // 鼠标按下事件
  operItem.addEventListener("mousedown", function (e) {
    if (e.button != 0) {
      return;
    }
    leftLabelIsMouseDown = true;
    unHilightLeftLabel(labelDivs, splitorDivs);
    leftLabelHaveDrawMarks = [];
    leftLabelMousemoveRowMarks = [row];
    parentObj.deSelectRect();
    parentObj.resetSelectRectSingle();
    parentObj.setSelectSingleStartRow(row);
    parentObj.selectRectRow(row);
    leftLabelSelectStartRow = row;
    leftLabelSelectEndRow = row;
    showHilight();
  });

  // 鼠标移动事件
  operItem.addEventListener("mousemove", function (e) {
    if (e.button != 0) {
      return;
    }
    e.preventDefault(); // 阻止默认事件，比如选中文本
    if (leftLabelIsMouseDown) {
      if (leftLabelMousemoveRowMarks.indexOf(row) == -1) {
        leftLabelMousemoveRowMarks.push(row);
        parentObj.setSelectSingleEndRow(row);
        parentObj.selectRectRow(row);
        leftLabelSelectEndRow = row;
        showHilight();
      }
    }
  });

  operItem.oncontextmenu = function (e) {
    e.preventDefault();
    if (leftLabelMousemoveRowMarks.indexOf(row) == -1) {
      return;
    }
    var pos = Comman.getMousePosition(
      operItem.parentElement.parentElement.parentElement,
      e.pageX,
      e.pageY
    );    
    var menuHeight = 80;
    pos.y = pos.y - menuHeight;
    parentObj.showLeftLabelContextMenu(pos);
  };

  function showHilight() {
    if (leftLabelSelectEndRow < leftLabelSelectStartRow) {
      var t = leftLabelSelectEndRow;
      leftLabelSelectEndRow = leftLabelSelectStartRow;
      leftLabelSelectStartRow = t;
    }
    for (var i = leftLabelSelectStartRow; i <= leftLabelSelectEndRow; i++) {
      if (leftLabelHaveDrawMarks.indexOf(i) != -1) {
        continue;
      }
      leftLabelHaveDrawMarks.push(i);
      showHilightLeftLabelOne(labelDivs, splitorDivs, i);
    }
  }
}

