  function color32ToRGBA(color32) {
    var alpha = color32 >> 24;
    var red = (color32 >> 16) & 0xff;
    var green = (color32 >> 8) & 0xff;
    var blue = color32 & 0xff;
    return { alpha: alpha, red: red, green: green, blue: blue };
  }

