  function setupButtonByMark(mark) {
    if (mark == "font") {
      setupFontToolbarButton();
    } else if (mark == "fontSize") {
      setupFontSizeToolbarButton();
    } else if (mark == "borderColor") {
      setupBorderColorPicker();
    } else if (mark == "borderStyle") {
      setupBorderStyleSelect();
    }
  }

