        var t1 = document.createElement("div");
        t1.style.width = "100%";
        t1.style.height = "20px";
        t1.style.textAlign = "center";
        t1.innerHTML = "检测结果标记";
        mainDiv.appendChild(t1);

        var t3 = document.createElement("div");
        t3.style.width = "100%";
        t3.style.height = "20px";
        t3.style.textAlign = "center";
        t3.style.color = "red";
        t3.style.fontSize = "8pt";
