/**
 * @fileoverview 填充数据通用工具类模块 - 提供日期解析、格式化、人民币大写转换等通用功能
 * @description 该模块提供了数据处理过程中常用的工具函数，
 * 包括日期解析、日期格式化、人民币大写转换、单元格尺寸获取等功能。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * 填充数据通用工具对象
 * @namespace Common
 * @description 提供日期解析、格式化、人民币大写转换等通用功能
 */
const Common = {
    /**
     * 大写日列表（1-31）
     * @type {string[]}
     */
    daxieriList: [
        "", "一", "二", "三", "四", "五", "六", "七", "八", "九", "十",
        "十一", "十二", "十三", "十四", "十五", "十六", "十七", "十八", "十九", "二十",
        "二十一", "二十二", "二十三", "二十四", "二十五", "二十六", "二十七", "二十八", "二十九", "三十",
        "三十一"
    ],

    /**
     * 大写月列表（1-12）
     * @type {string[]}
     */
    daxieyueList: ["", "一", "二", "三", "四", "五", "六", "七", "八", "九", "十", "十一", "十二"],

    /**
     * 大写年数字列表（0-9）
     * @type {string[]}
     */
    daxienianList: ["○", "一", "二", "三", "四", "五", "六", "七", "八", "九"],

    /**
     * 解析日期字符串
     * @param {string} dateStr - 日期字符串
     * @returns {Date} 解析后的日期对象
     * @throws {Error} 当日期格式无法识别时抛出错误
     */
    ParseDate: function (dateStr) {
        const patterns = [
            /(\d{4})年(\d{1,2})月(\d{1,2})日.*/,
            /(\d{4})-(\d{1,2})-(\d{1,2}).*/,
            /(\d{4})\/(\d{1,2})\/(\d{1,2}).*/,
            /(\d{1,2})\/(\d{1,2})\/(\d{4}).*/
        ];

        let year = -1, month = -1, day = -1;

        for (let i = 0; i < patterns.length; i++) {
            const match = dateStr.match(patterns[i]);
            if (match) {
                if (i === 3) {
                    year = parseInt(match[3]);
                    month = parseInt(match[1]);
                    day = parseInt(match[2]);
                } else {
                    year = parseInt(match[1]);
                    month = parseInt(match[2]);
                    day = parseInt(match[3]);
                }
                break;
            }
        }

        if (year !== -1 && month !== -1 && day !== -1) {
            return new Date(Date.UTC(year, month - 1, day, 0, 0, 0));
        }

        throw new Error(`将${dateStr}转换成日期格式失败!`);
    },

    /**
     * 合并PDF文件（待实现）
     * @param {string[]} inputPdfFiles - 输入PDF文件列表
     * @param {string} outputPdfFile - 输出PDF文件路径
     * @returns {Promise<void>}
     */
    MergePdfFiles: async function (inputPdfFiles, outputPdfFile) {
    },

    /**
     * 解析日期时间字符串
     * @param {string} dateTimeStr - 日期时间字符串
     * @returns {Date} 解析后的日期对象
     */
    ParseDateTime: function (dateTimeStr) {
        const timePattern = '[ T](\\d{1,2})[:时](\\d{1,2})[:分](\\d{1,2}).*';
        const patterns = [
            new RegExp(`(\\d{4})年(\\d{1,2})月(\\d{1,2})日${timePattern}`),
            new RegExp(`(\\d{4})-(\\d{1,2})-(\\d{1,2})${timePattern}`),
            new RegExp(`(\\d{4})\/(\\d{1,2})\/(\\d{1,2})${timePattern}`),
            new RegExp(`(\\d{1,2})\/(\\d{1,2})\/(\\d{4})${timePattern}`)
        ];

        let year = -1, month = -1, day = -1, hour = -1, minute = -1, second = -1;

        for (let i = 0; i < patterns.length; i++) {
            const match = dateTimeStr.match(patterns[i]);
            if (match) {
                if (i === 3) {
                    year = parseInt(match[3]);
                    month = parseInt(match[1]);
                    day = parseInt(match[2]);
                    hour = parseInt(match[4]);
                    minute = parseInt(match[5]);
                    second = parseInt(match[6]);
                } else {
                    year = parseInt(match[1]);
                    month = parseInt(match[2]);
                    day = parseInt(match[3]);
                    hour = parseInt(match[4]);
                    minute = parseInt(match[5]);
                    second = parseInt(match[6]);
                }
                break;
            }
        }

        if (year !== -1 && month !== -1 && day !== -1 && hour !== -1 && minute !== -1 && second !== -1) {
            return new Date(Date.UTC(year, month - 1, day, hour, minute, second));
        } else {
            return this.ParseDate(dateTimeStr);
        }
    },

    /**
     * 去除字符串首尾的标点符号
     * @param {string} str - 原字符串
     * @returns {string} 处理后的字符串
     */
    TrimS: function (str) {
        while (true) {
            let original = str;
            str = str.replace(/^[、,，；]|[、,，；]$/, '');
            if (str === original) {
                break;
            }
        }
        return str;
    },

    /**
     * 写入日志（Node.js环境）
     * @param {string} message - 日志消息
     */
    WriteLog: function (message) {
        const logFile = 'H:\\A\\TestReportGenDll_java_metaData\\log.txt';
        const timestamp = new Date().toISOString().replace(/T/, ' ').replace(/\..+/, '');
        const logMessage = `${timestamp}: ${message}`;
        if (typeof fs !== 'undefined') {
            fs.appendFileSync(logFile, logMessage + '\n', 'utf8');
        }
    },

    /**
     * 获取单元格尺寸
     * @param {Object} cell - 单元格对象
     * @param {number} col - 列号
     * @param {number} row - 行号
     * @param {Object} sheet - 工作表对象
     * @returns {Object} 包含height和width的对象
     */
    GetCellSize: function (cell, col, row, sheet) {
        let startCol = 0, startRow = 0, endCol = 0, endRow = 0;
        let cellSize = { height: 0, width: 0 };

        if (cell.GetMergeRange(col, row, startCol, startRow, endCol, endRow) === 1) {
            cellSize.height = this.GetRowHeight(cell, startRow, endRow);
            cellSize.width = this.GetColWidth(cell, startCol, endCol);
        } else {
            cellSize.height = this.GetRowHeight(cell, row, row);
            cellSize.width = this.GetColWidth(cell, col, col);
        }

        return cellSize;
    },

    /**
     * 获取列宽度总和
     * @param {Object} cell - 单元格对象
     * @param {number} startCol - 起始列
     * @param {number} endCol - 结束列
     * @returns {number} 列宽度总和
     */
    GetColWidth: function (cell, startCol, endCol) {
        var totalWidth = 0;
        for (var col = startCol; col <= endCol; col++) {
            totalWidth += cell.GetColWidth(0, col, 0);
        }
        return totalWidth;
    },

    /**
     * 获取行高度总和
     * @param {Object} cell - 单元格对象
     * @param {number} startRow - 起始行
     * @param {number} endRow - 结束行
     * @returns {number} 行高度总和
     */
    GetRowHeight: function (cell, startRow, endRow) {
        var totalHeight = 0;
        for (var row = startRow; row <= endRow; row++) {
            totalHeight += cell.GetRowHeight(0, row, 0);
        }
        return totalHeight;
    },

    /**
     * 获取格式化的日期字符串
     * @param {string} dateStr - 日期字符串
     * @param {string} dateFormat - 日期格式
     * @returns {string} 格式化后的日期字符串
     */
    GetDateStr: function (dateStr, dateFormat) {
        try {
            var date = this.ParseDate(dateStr);
            return formatDate(date, dateFormat);
        } catch (e) {
            return dateStr;
        }
    },

    /**
     * 获取格式化的日期时间字符串
     * @param {string} dateTimeStr - 日期时间字符串
     * @param {string} dateTimeFormat - 日期时间格式
     * @returns {string} 格式化后的日期时间字符串
     */
    GetDateTimeStr: function (dateTimeStr, dateTimeFormat) {
        try {
            var dateTime = this.ParseDateTime(dateTimeStr);
            return formatDate(dateTime, dateTimeFormat);
        } catch (e) {
            return dateTimeStr;
        }
    },

    /**
     * 获取格式化的时间字符串
     * @param {string} timeStr - 时间字符串
     * @param {string} timeFormat - 时间格式
     * @returns {string} 格式化后的时间字符串
     */
    GetTimeStr: function (timeStr, timeFormat) {
        try {
            var dateTime = this.ParseDateTime(timeStr);
            return formatDate(dateTime, timeFormat);
        } catch (e) {
            return timeStr;
        }
    },

    /**
     * 获取大写中文年月日字符串
     * @param {string} dateStr - 日期字符串
     * @returns {string} 大写中文年月日字符串
     */
    GetDateDaxienianyueriStr: function (dateStr) {
        try {
            var date = this.ParseDateTime(dateStr);
            var year = date.getFullYear();
            var month = date.getMonth() + 1;
            var day = date.getDate();

            var yearStr = this.GetNumberDaxienian(year);
            var monthStr = this.GetNumberDaxieyue(month);
            var dayStr = this.GetNumberDaxieri(day);

            return yearStr + "年" + monthStr + "月" + dayStr + "日";
        } catch (e) {
            return dateStr;
        }
    },

    /**
     * 获取大写日
     * @param {number} day - 日（1-31）
     * @returns {string} 大写日字符串
     */
    GetNumberDaxieri: function (day) {
        return this.daxieriList[day];
    },

    /**
     * 获取大写月
     * @param {number} month - 月（1-12）
     * @returns {string} 大写月字符串
     */
    GetNumberDaxieyue: function (month) {
        return this.daxieyueList[month];
    },

    /**
     * 获取大写年
     * @param {number} year - 年
     * @returns {string} 大写年字符串
     */
    GetNumberDaxienian: function (year) {
        var yearStr = year.toString();
        var result = '';

        for (var i = 0; i < yearStr.length; i++) {
            var digit = parseInt(yearStr.charAt(i), 10);
            result += this.daxienianList[digit];
        }

        return result;
    },

    /**
     * 获取大写中文年月字符串
     * @param {string} dateStr - 日期字符串
     * @returns {string} 大写中文年月字符串
     */
    GetDateDaxienianyueStr: function (dateStr) {
        try {
            var date = this.ParseDateTime(dateStr);
            var year = date.getFullYear();
            var month = date.getMonth() + 1;

            var yearStr = this.GetNumberDaxienian(year);
            var monthStr = this.GetNumberDaxieyue(month);

            return yearStr + "年" + monthStr + "月";
        } catch (e) {
            return dateStr;
        }
    },

    /**
     * 获取人民币大写字符串
     * @param {string|number} amount - 金额
     * @returns {string} 人民币大写字符串
     */
    GetRenmingbidaxieStr: function (amount) {
        try {
            return ConvertUpMoney.ToChinese(amount);
        } catch (e) {
            return amount;
        }
    }
};

/**
 * @fileoverview 金额转大写工具类模块 - 将数字金额转换为人民币大写格式
 * @description 该模块提供了将阿拉伯数字金额转换为中文大写金额的功能，
 * 支持整数和小数部分的转换，支持负数金额，最大支持千万亿级别。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * 金额转大写工具对象
 * @namespace ConvertUpMoney
 * @description 提供数字金额转中文大写金额的功能
 */
var ConvertUpMoney = {
    /**
     * 数字对应的大写字符
     * @type {string[]}
     */
    NUMBERS: ["零", "壹", "贰", "叁", "肆", "伍", "陆", "柒", "捌", "玖"],

    /**
     * 整数部分的数位单位
     * @type {string[]}
     */
    IUNIT: ["元", "拾", "佰", "仟", "万", "拾", "佰", "仟", "亿", "拾", "佰", "仟", "万", "拾", "佰", "仟"],

    /**
     * 小数部分的单位
     * @type {string[]}
     */
    DUNIT: ["角", "分", "厘"],

    /**
     * 将数字金额转换为中文大写金额
     * @param {string|number} amount - 金额字符串或数字
     * @returns {string} 中文大写金额
     */
    ToChinese: function (amount) {
        var str = String(amount);

        if (!str || !/^\d*(\.\d*)?$/.test(str)) {
            console.log("抱歉，请输入数字！");
            return str;
        }

        if (str === "0" || str === "0.00" || str === "0.0") {
            return "零元";
        }

        var isNegative = false;
        if (str.indexOf("-") === 0) {
            isNegative = true;
            str = str.replace("-", "");
        }

        str = str.replace(',', '.');

        var integerStr, decimalStr;

        if (str.indexOf(".") > -1) {
            integerStr = str.split(".")[0];
            decimalStr = str.split(".")[1];
        } else if (str.indexOf(".") === 0) {
            integerStr = "";
            decimalStr = str.substring(1);
        } else {
            integerStr = str;
            decimalStr = "";
        }

        if (integerStr.length > ConvertUpMoney.IUNIT.length) {
            console.log(str + "：超出计算能力");
            return str;
        }

        var integers = ConvertUpMoney.ToIntArray(integerStr);

        if (integers.length > 1 && integers[0] === 0) {
            console.log("抱歉，请输入数字！");
            return isNegative ? "-" + str : str;
        }

        var isWan = ConvertUpMoney.IsWanUnits(integerStr);
        var decimals = ConvertUpMoney.ToIntArray(decimalStr);

        var result = ConvertUpMoney.GetChineseInteger(integers, isWan) + ConvertUpMoney.GetChineseDecimal(decimals);

        return isNegative ? "负" + result : result;
    },

    /**
     * 将数字字符串转为数字数组
     * @param {string|number} number - 数字字符串或数字
     * @returns {number[]} 数字数组
     */
    ToIntArray: function (number) {
        return number.toString().split('').map(Number);
    },

    /**
     * 将整数部分转为大写的金额
     * @param {number[]} integers - 整数位数组
     * @param {boolean} isWan - 是否达到万位
     * @returns {string} 中文大写金额整数部分
     */
    GetChineseInteger: function (integers, isWan) {
        var chineseInteger = "";
        var length = integers.length;

        if (length === 1 && integers[0] === 0) {
            return "";
        }

        for (var i = 0; i < length; i++) {
            var key = "";

            if (integers[i] === 0) {
                if ((length - i) === 13) {
                    key = ConvertUpMoney.IUNIT[4];
                } else if ((length - i) === 9) {
                    key = ConvertUpMoney.IUNIT[8];
                } else if ((length - i) === 5 && isWan) {
                    key = ConvertUpMoney.IUNIT[4];
                } else if ((length - i) === 1) {
                    key = ConvertUpMoney.IUNIT[0];
                }

                if ((length - i) > 1 && integers[i + 1] !== 0) {
                    key += ConvertUpMoney.NUMBERS[0];
                }
            }

            chineseInteger += integers[i] === 0
                ? key
                : (ConvertUpMoney.NUMBERS[integers[i]] + ConvertUpMoney.IUNIT[length - i - 1]);
        }

        return chineseInteger;
    },

    /**
     * 将小数部分转为大写的金额
     * @param {number[]} decimals - 小数位数组
     * @returns {string} 中文大写金额小数部分
     */
    GetChineseDecimal: function (decimals) {
        var chineseDecimal = "";

        for (var i = 0; i < decimals.length; i++) {
            if (i === 3) break;
            chineseDecimal += decimals[i] === 0
                ? ""
                : (ConvertUpMoney.NUMBERS[decimals[i]] + ConvertUpMoney.DUNIT[i]);
        }

        return chineseDecimal;
    },

    /**
     * 判断当前整数部分是否已经达到【万】
     * @param {string} integerStr - 整数部分字符串
     * @returns {boolean} 是否达到万位
     */
    IsWanUnits: function (integerStr) {
        var length = integerStr.length;

        if (length > 4) {
            var subInteger = "";
            if (length > 8) {
                subInteger = integerStr.substring(length - 8, length - 4);
            } else {
                subInteger = integerStr.substring(0, length - 4);
            }
            return parseInt(subInteger) > 0;
        } else {
            return false;
        }
    }
};

/**
 * @fileoverview 结束执行模块 - 负责报表生成结束后的处理工作
 * @description 该模块负责报表生成结束后的收尾工作，
 * 包括生成报表输出信息、填充页码等功能。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * @fileoverview 结束执行模块 - 负责报表生成结束后的处理工作
 * @description 该模块负责报表生成结束后的收尾工作，
 * 包括生成报表输出信息、填充页码等功能。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * 结束执行类
 * @class EndDo
 * @description 负责报表生成结束后的处理工作
 */
function EndDo() {
    /**
     * 获取报表生成输出信息
     * @function GetGenReportOutInfo
     * @param {Array} fillOneTemplateOutInfoListAll - 所有填充模板输出信息列表
     * @param {Object} fillReportSysInfo - 填充报表系统信息
     * @returns {Object} 报表生成输出信息
     */
    this.GetGenReportOutInfo = function (fillOneTemplateOutInfoListAll, fillReportSysInfo) {
        this.FillPageNo(fillOneTemplateOutInfoListAll);

        var genReportOutInfo = {
            outFileList: []
        };

        fillOneTemplateOutInfoListAll.forEach(function (fillOneTemplateOutInfo) {
            var cellSheet = fillOneTemplateOutInfo.cellSheet;
            genReportOutInfo.outFileList.push(cellSheet);
        }, this);

        return genReportOutInfo;
    };

    /**
     * 填充页码
     * @param {Array} fillOneTemplateOutInfoList - 填充模板输出信息列表
     */
    this.FillPageNo = function (fillOneTemplateOutInfoList) {
        var totalPageCount = 0;

        fillOneTemplateOutInfoList.forEach(function (fillOneTemplateOutInfo) {
            totalPageCount += fillOneTemplateOutInfo.pageNoColRowInfoList.length;
        });

        var pageNo = 1;

        fillOneTemplateOutInfoList.forEach(function (fillOneTemplateOutInfo) {
            var cell = fillOneTemplateOutInfo.cell;

            fillOneTemplateOutInfo.pageNoColRowInfoList.forEach(function (pageNoColRowInfo) {
                cell.SetCellString(pageNoColRowInfo.col, pageNoColRowInfo.row, 0, '第' + pageNo + '页 共' + totalPageCount + '页');
                pageNo++;
            });
        });
    };
}

/**
 * @fileoverview 填充数据模块 - 负责将数据填充到报表模板中
 * @description 该模块是报表数据填充的核心模块，负责将JSON数据填充到报表模板中，
 * 支持多种数据类型转换、签名图片插入、浮动印章等功能。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * 填充数据映射（列行 -> 表名.列名.记录号）
 * @type {Object}
 * @description 存储单元格位置到数据字段的映射关系
 */
let fillDataMaps1 = {};

/**
 * 填充数据映射（表名.列名.记录号 -> 列行集合）
 * @type {Object}
 * @description 存储数据字段到单元格位置的映射关系
 */
let fillDataMaps2 = {};

/**
 * 填充数据JSON数据
 * @type {Array}
 * @description 存储待填充的JSON数据
 */
let fillDataJsonData = [];

/**
 * 是否需要记录填充数据映射
 * @type {boolean}
 * @description 控制是否记录填充数据映射关系
 */
let isNeedRecordRecordFillDataMaps = false;

/**
 * 是否正在填充数据
 * @type {boolean}
 * @description 标记当前是否处于填充数据过程中
 */
let isInFillDataing = false;

/**
 * 需要设置的复选框信息列表
 * @type {Array}
 * @description 存储需要设置为复选框的单元格信息
 */
let needSetCheckBoxInfoList = [];

/**
 * 填充数据类
 * @class FillData
 * @description 负责将数据填充到报表模板中
 * @param {Object} parentObj - 父对象，用于回调绘制方法
 * @returns {Object} 包含DoJob方法的对象
 */
function FillData(parentObj) {
    var isFirstTime = true;

    /**
     * 执行填充数据任务
     * @param {Object} config - 配置对象
     * @param {string} config.jsonDataStr - JSON数据字符串
     * @param {Array} config.reportTemplateList - 报表模板列表
     * @param {Array} config.reportTemplateConditionInfoList - 报表模板条件信息列表
     * @param {Array} config.reportTemplatePrintParamList - 报表模板打印参数列表
     * @param {Object} config.fillReportSysInfo - 填充报表系统信息
     * @param {boolean} config.isOnlyNeedRedrawText - 是否只需要重绘文本
     */
    function DoJob(config) {
        fillDataMaps1 = {};
        fillDataMaps2 = {};
        isInFillDataing = true;
        var result = fillData(config);
        isInFillDataing = false;

        if (isFirstTime) {
            isFirstTime = false;
            parentObj.drawCellDataFirstTime(result);
        } else {
            parentObj.resetCellData(result, config.isOnlyNeedRedrawText, true);
        }
    }

    /**
     * 执行填充数据
     * @param {Object} config - 配置对象
     * @returns {Object} 生成的报表输出信息
     */
    function fillData(config) {
        var jsonDataStr = config.jsonDataStr;
        var reportTemplateList = config.reportTemplateList;
        var reportTemplateConditionInfoList = config.reportTemplateConditionInfoList;
        var reportTemplatePrintParamList = config.reportTemplatePrintParamList;
        var fillReportSysInfo = config.fillReportSysInfo;

        var fillOneTemplateOutInfoListAll = [];

        var startDo = StartDo.CreateStartDo(
            jsonDataStr,
            reportTemplateList,
            reportTemplateConditionInfoList,
            reportTemplatePrintParamList,
            fillReportSysInfo
        );
        var fillOneTemplateOutInfoList1 = startDo.GenReport();
        fillOneTemplateOutInfoListAll = fillOneTemplateOutInfoListAll.concat(fillOneTemplateOutInfoList1);

        var endDo = new EndDo();
        var genReportOutInfo = endDo.GetGenReportOutInfo(fillOneTemplateOutInfoListAll, fillReportSysInfo);
        var result = genReportOutInfo.outFileList[0];

        return result;
    }

    return {
        DoJob: DoJob
    };
}

'use strict';

/**
 * @fileoverview 填充单份报表副本模块 - 负责填充单个报表副本的数据
 * @description 该模块负责将数据填充到单个报表副本中，
 * 处理单元格字符串解析、数据替换、签名图片插入、浮动印章绘制等功能。
 * @author MyCell Designer
 * @version 1.0.0
 */

/**
 * 是否调试模式
 * @type {boolean}
 * @description 控制是否启用调试模式
 */
let isDebug = false;

/**
 * 填充单份报表副本类
 * @class FillOneReportCopy
 * @description 负责填充单个报表副本的数据
 * @param {Object} cell - 单元格操作对象
 * @param {Object} rsAll - 所有数据记录集
 * @param {Object} printParam - 打印参数
 * @param {number} copyNum - 副本编号
 * @param {number} fillStartRow - 填充起始行
 * @param {Array} reportBodyList - 报表主体列表
 * @param {number} totalRecordCount - 总记录数
 * @param {Object} fillReportSysInfo - 填充报表系统信息
 */
function FillOneReportCopy(cell, rsAll, printParam, copyNum, fillStartRow, reportBodyList, totalRecordCount, fillReportSysInfo) {
    this.cell = cell;
    this.rsAll = rsAll;
    this.printParam = printParam;
    this.copyNum = copyNum;
    this.fillStartRow = fillStartRow;
    this.reportBodyList = reportBodyList;
    this.totalRecordCount = totalRecordCount;
    this.fillReportSysInfo = fillReportSysInfo;
    this.pageNoColRowInfoList = [];
    this.haveFillEmptyStrBodyIndexList = [];
    this.fillOneReportOutInfo = {
        specialColumnFillInfoList: []
    };

    this.DoJob = function () {
        var cols = this.cell.GetCols(0) - 1;
        var rows = this.cell.GetRows(0) - 1;
        for (var col = 1; col <= cols; col++) {
            for (var row = 1; row <= rows; row++) {
                var s = this.cell.GetCellString(col, row, 0);
                if (s.indexOf("[#") !== -1 && s.indexOf("#]") !== -1) {
                    if (!isDebug) {
                        this.FillOneStr(col, row, s);
                    }
                }
                else {
                    this.cell.SetCellReadOnly(col, row, 0, true);
                }
            }
        }

        //合并相关单元格信息    
        this.CombinNeedCombinInfo();

        //填充序号    
        this.FillXuHao();

        //填充以下空白    
        this.FillBodyBlankStr();

        return this.pageNoColRowInfoList;
    };

    this.FillBodyBlankStr = function () {
        var L = this.fillOneReportOutInfo.specialColumnFillInfoList.filter(function (p) {
            return p.type === FillBodyBlankType.以下空白;
        });

        if (L.length === 0) {
            return;
        }

        if (this.fillReportSysInfo.fillBodyBlankType === FillBodyBlankType.默认) {
            var L1 = [];
            L.forEach(function (p) {
                var t = p.bodyIndex;
                if (L1.indexOf(t) === -1) {
                    L1.push(t);
                }
            });
            L1.forEach(function (bodyIndex) {
                var L2 = L.filter(function (p) {
                    return p.bodyIndex === bodyIndex;
                });
                if (reportBodyList[bodyIndex].orientation === "横向") {
                    this.ClearBodyRangeH(L2);
                } else {
                    this.ClearBodyRangeV(L2);
                }
            }, this);
        } else {
            throw new Error("填充以下空白方式有待实现!");
        }
    };

    this.ClearBodyRangeV = function (L) {
        var isHaveFilledEmptyFillStr = false;
        var reportBody = this.reportBodyList[L[0].bodyIndex];
        L.forEach(function (p) {
            var col = p.col;
            var row = p.row;
            if (!isHaveFilledEmptyFillStr) {
                var cellSize = Common.GetCellSize(this.cell, col, row, 0);
                if (cellSize.height > 10 && cellSize.width > 20) {
                    this.cell.SetCellString(col, row, 0, this.fillReportSysInfo.emptyFillStrV);
                    this.FillEmptyToEnd(col, reportBody.endCol, row, reportBody.endRow);
                    isHaveFilledEmptyFillStr = true;
                }
            }
        }, this);
    };

    this.FillEmptyToEnd = function (startCol, endCol, startRow, endRow) {
        for (var col = startCol; col <= endCol; col++) {
            for (var row = startRow; row <= endRow; row++) {
                if (col === startCol && row === startRow) {
                    continue;
                }
                this.cell.SetCellString(col, row, 0, "");
            }
        }
    };

    this.ClearBodyRangeH = function (L) {
        var isHaveFilledEmptyFillStr = false;
        var reportBody = this.reportBodyList[L[0].bodyIndex];
        L.forEach(function (p) {
            var col = p.col;
            var row = p.row;
            if (!isHaveFilledEmptyFillStr) {
                var cellSize = Common.GetCellSize(this.cell, col, row, 0);
                if (cellSize.height > 10 && cellSize.width > 20) {
                    this.cell.SetCellString(col, row, 0, this.fillReportSysInfo.emptyFillStrH);
                    this.FillEmptyToEnd(col, reportBody.endCol, row, reportBody.endRow);
                    isHaveFilledEmptyFillStr = true;
                }
            }
        }, this);
    };

    this.FillXuHao = function () {
        var L = this.fillOneReportOutInfo.specialColumnFillInfoList.filter(function (p) {
            return p.type === SpecialColumnType.序号;
        });

        if (L.length === 0) {
            return;
        }

        if (this.fillReportSysInfo.fillXuHaoType === FillXuHaoType.默认) {
            L.forEach(function (p) {
                this.cell.SetCellString(p.col, p.row, 0, p.s);
            }, this);
        } else {
            throw new Error("填充序号方式有待实现!");
        }
    };

    this.CombinNeedCombinInfo = function () {
        // 实现代码  
    };

    this.FillOneStr = function (col, row, s) {
        while (true) {
            var pos1 = s.indexOf("[#");
            if (pos1 === -1) return;

            var pos2 = s.indexOf("#]", pos1 + 2);
            if (pos2 === -1) return;

            var tt = s.substring(pos1, pos2 + 2 - pos1);
            var t = s.substring(pos1 + 2, pos2 - pos1);
            var tAr = t.split(/\.|。/);

            var t1 = {
                tableName: tAr[0],
                columnName: tAr[1],
                bodyIndex: parseInt(tAr[2]) - 1,
                recNum: parseInt(tAr[3]) - 1,
                dataType: tAr.length > 4 ? tAr[4].toLowerCase() : "c"
            };

            this.cell.SetCellFillDataType(col, row, 0, t1.dataType);

            this.recordFillDataMaps(col, row, s, t1);

            var o = needSetCheckBoxInfoList.find(p => p.tableNameAndColumn == t1.tableName + "." + t1.columnName);            
            if (o != null) {
                var v = "";
                var rs = this.rsAll[t1.tableName];
                if (rs && rs[t1.recNum]) {
                    v = rs[t1.recNum][t1.columnName] || "";
                }                
                if (v == "") {
                    v = o.defaultValue;
                }
                this.cell.SetCellString(col, row, 0, v);
                this.cell.SetCellIsCheckBox(col, row, 0, true);
                return;
            }

            if (t1.tableName === "ccc") {
                if (t1.columnName === "xuhao") {
                    var recNum = this.printParam.recordPerPage * this.copyNum + t1.recNum;
                    if (recNum < this.totalRecordCount) {
                        this.fillOneReportOutInfo.specialColumnFillInfoList.push({
                            col: col,
                            row: row,
                            s: (recNum + 1).toString(),
                            bodyIndex: t1.bodyIndex,
                            type: SpecialColumnType.序号
                        });
                    }
                    this.cell.SetCellString(col, row, 0, "");
                    s = "";
                } else if (t1.columnName === "pageofreport") {
                    this.pageNoColRowInfoList.push({ col: col, row: row });
                    this.cell.SetCellString(col, row, 0, "");
                    s = "";
                }
                else{
                    return;
                }
            } else {
                s = this.FillOneStr2(col, row, t1, s, tt);
                var o = this.GetSignNameInfo(t1);
                if (o) {
                    this.FillOneStrAndSignName(col, row, t1, s, o);
                }
                var o1 = this.GetFloatSealInfo(t1, s);
                if (o1) {
                    this.DrawFloatSeal(col, row, t1, s, o1);
                }
            }
        }
    };

    this.recordFillDataMaps = function (col, row, s, t1) {
        var recNum = this.printParam.recordPerPage * this.copyNum + t1.recNum;
        var t2 = col + "." + row;
        var t3 = t1.tableName + "." + t1.columnName + "." + recNum;
        if (fillDataMaps1[t2]) {
            throw "一个单元格里面只能有一个字段!单元格(" + col + ", " + row + ")字符串内容为:" + s + ",不符合模板设计要求，请修正模板!";
        }
        fillDataMaps1[t2] = { tableName: t1.tableName, columnName: t1.columnName, recNum: recNum };
        ;
        fillDataMaps2[t3] = { col: col, row: row };
        ;
    }

    this.GetFloatSealInfo = function (t1, s) {
        var t = t1.tableName + "." + t1.columnName;
        for (var i = 0; i < this.fillReportSysInfo.floatSealInfoList.length; i++) {
            var p = this.fillReportSysInfo.floatSealInfoList[i];
            if (p.relTableNameAndColumn === t) return p;
            for (var j = 0; j < p.conditionWordList.length; j++) {
                if (s.indexOf(p.conditionWordList[j]) !== -1) return p;
            }
        }
        return null;
    };

    this.DrawFloatSeal = function (col, row, t1, s, o) {
        // 实现绘制浮动图章的逻辑  
    };

    this.FillOneStrAndSignName = function (col, row, t1, s, o) {
        if (o.position === SignNamePosition.仅签名图片) {
            this.cell.SetCellString(col, row, 0, "");
            var index = this.cell.AddImage(o.imagePath);
            this.cell.SetCellImage(col, row, 0, index, 3, 2, 2);
            return;
        }
        if (o.position === SignNamePosition.仅名字) return;
        if (o.position === SignNamePosition.签名图片居上名字居下) {
            this.cell.SetCellAlign(col, row, 0, 4 + 16);
            var index = this.cell.AddImage(o.imagePath);
            this.cell.SetCellImage(col, row, 0, index, 3, 2, 1);
            return;
        }
        if (o.position === SignNamePosition.签名图片居下名字居上) {
            this.cell.SetCellAlign(col, row, 0, 4 + 8);
            var index = this.cell.AddImage(o.imagePath);
            this.cell.SetCellImage(col, row, 0, index, 3, 2, 3);
            return;
        }
        if (o.position === SignNamePosition.签名图片居右名字居左) {
            this.cell.SetCellAlign(col, row, 0, 1 + 32);
            var index = this.cell.AddImage(o.imagePath);
            this.cell.SetCellImage(col, row, 0, index, 3, 3, 2);
            return;
        }
        if (o.position === SignNamePosition.签名图片居左名字居右) {
            this.cell.SetCellAlign(col, row, 0, 2 + 32);
            var index = this.cell.AddImage(o.imagePath);
            this.cell.SetCellImage(col, row, 0, index, 3, 1, 2);
            return;
        }
    };

    this.GetSignNameInfo = function (t1) {
        var t = t1.tableName + "." + t1.columnName;
        for (var i = 0; i < this.fillReportSysInfo.signNameInfoList.length; i++) {
            if (this.fillReportSysInfo.signNameInfoList[i].relTableNameAndColumn === t) {
                return this.fillReportSysInfo.signNameInfoList[i];
            }
        }
        return null;
    };

    this.FillOneStr2 = function (col, row, t1, s, tt) {
        var t2 = "", t = "";

        if (!this.rsAll[t1.tableName]) {
            t2 = s.replace(tt, this.fillReportSysInfo.blankFillStr);
            this.cell.SetCellString(col, row, 0, t2);
            return t2;
        }

        var rs = this.rsAll[t1.tableName];

        if (rs.length === 0) {
            t2 = s.replace(tt, this.fillReportSysInfo.blankFillStr);
            this.cell.SetCellString(col, row, 0, t2);
            return t2;
        }

        var recNum = this.printParam.recordPerPage * this.copyNum + t1.recNum;

        if (t1.bodyIndex >= 0 && recNum >= rs.length) {
            this.cell.SetCellString(col, row, 0, "");
            var t3 = {
                col: col,
                row: row,
                s: (recNum + 1).toString(),
                bodyIndex: t1.bodyIndex,
                type: SpecialColumnType.以下空白
            };
            this.fillOneReportOutInfo.specialColumnFillInfoList.push(t3);
            return "";
        }

        if (t1.bodyIndex === -1 && recNum >= rs.length) {
            t = this.GetOneColumnValue(rs, 0, t1);
            t2 = s.replace(tt, t);
            t2 = this.TrimS(t2);
            this.cell.SetCellString(col, row, 0, t2);
            return t2;
        }

        t = this.GetOneColumnValue(rs, recNum, t1);
        t2 = s.replace(tt, t);
        t2 = this.TrimS(t2);
        this.cell.SetCellString(col, row, 0, t2);
        return t2;
    };

    this.TrimS = function (s) {
        s = Common.TrimS(s);
        if (!s) {
            return this.fillReportSysInfo.blankFillStr;
        }
        return s;
    };

    this.GetOneColumnValue = function (rs, recNum, t1) {
        var t = rs[recNum];
        if (!t) {
            return this.fillReportSysInfo.blankFillStr;
        }
        if (t[t1.columnName]) {
            var t2 = t[t1.columnName].toString();

            if (t2) {
                if (t1.dataType === "d") {
                    return Common.GetDateStr(t2, this.fillReportSysInfo.dateFormat);
                } else if (t1.dataType === "d1") {
                    return Common.GetDateDaxienianyueriStr(t2);
                } else if (t1.dataType === "d2") {
                    return Common.GetDateDaxienianyueStr(t2);
                } else if (t1.dataType === "t1") {
                    return Common.GetDateTimeStr(t2, this.fillReportSysInfo.dateTimeFormat);
                } else if (t1.dataType === "t2") {
                    return Common.GetTimeStr(t2, this.fillReportSysInfo.timeFormat);
                } else if (t1.dataType === "n1") {
                    return Common.GetRenmingbidaxieStr(t2);
                }
            }
            return t2;
        }
        return this.fillReportSysInfo.blankFillStr;
    };
}
/**
 * @fileoverview 填充单个模板模块 - 负责填充单个报表模板的数据
 * @description 该模块负责填充单个报表模板的数据，
 * 包括计算每页记录数、复制模板、填充数据等功能。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * 填充单个模板类
 * @class FillOneTemplate
 * @description 负责填充单个报表模板的数据
 * @param {Object} rsAll - 所有结果集数据
 * @param {Object} cell - 单元格操作对象
 * @param {Object} printParam - 打印参数
 * @param {Object} fillReportSysInfo - 填充报表系统信息
 */
function FillOneTemplate(rsAll, cell, printParam, fillReportSysInfo) {
    /**
     * 所有结果集数据
     * @type {Object}
     */
    this.rsAll = rsAll;

    /**
     * 单元格操作对象
     * @type {Object}
     */
    this.cell = cell;

    /**
     * 打印参数
     * @type {Object}
     */
    this.printParam = printParam;

    /**
     * 报表主体新增行数
     * @type {number}
     */
    this.reportBodyAddRows = 0;

    /**
     * 总记录数
     * @type {number}
     */
    this.totalRecordCount = 0;

    /**
     * 填充报表系统信息
     * @type {Object}
     */
    this.fillReportSysInfo = fillReportSysInfo;

    /**
     * 填充模板输出信息
     * @type {Object}
     */
    this.fillOneTemplateOutInfo = {
        pageNoColRowInfoList: []
    };

    if (this.printParam.recordPerPage === -1) {
        this.printParam.recordPerPage = this.GetRecordPerPage();
    }
}

/**
 * 执行填充任务
 * @returns {Object} 填充模板输出信息
 */
FillOneTemplate.prototype.DoJob = function () {
    this.totalRecordCount = this.GetTotalRecordCount();
    var reportCopy = this.GetReportCopy();
    this.CopyAndPasteContentThenFill(reportCopy);
    return this.fillOneTemplateOutInfo;
};

/**
 * 获取每页记录数
 * @returns {number} 每页记录数
 */
FillOneTemplate.prototype.GetRecordPerPage = function () {
    if (this.printParam.reportBodyList.length > 0) {
        return this.GetRecordPerPageByReportBody();
    } else {
        return 1;
    }
};

/**
 * 通过报表主体获取每页记录数
 * @returns {number} 每页记录数
 */
FillOneTemplate.prototype.GetRecordPerPageByReportBody = function () {
    var maxRecordPerPage = 0;
    for (var i = 0; i < this.printParam.reportBodyList.length; i++) {
        var recordPerPage = this.GetRecordPerPageByReportBodyOne(this.printParam.reportBodyList[i]);
        if (recordPerPage > maxRecordPerPage) {
            maxRecordPerPage = recordPerPage;
        }
    }
    return maxRecordPerPage;
};

/**
 * 通过单个报表主体获取每页记录数
 * @param {Object} reportBody - 报表主体对象
 * @returns {number} 每页记录数
 */
FillOneTemplate.prototype.GetRecordPerPageByReportBodyOne = function (reportBody) {
    var maxRecNum = 0;
    var tableName = this.printParam.tablesUsedToRecordCount;

    for (var col = reportBody.startCol; col <= reportBody.endCol; col++) {
        for (var row = reportBody.startRow; row <= reportBody.endRow; row++) {
            var cellString = this.cell.GetCellString(col, row, 0);
            if (cellString.indexOf("[#") != -1 && cellString.indexOf("#]") != -1) {
                var refInfo = getCellRefTableNameAndColumnInfo(cellString);
                if (refInfo.tableName == tableName) {
                    var recNum = Number(refInfo.recNum);
                    if (recNum > maxRecNum) {
                        maxRecNum = recNum;
                    }
                }
            }
        }
    }
    return maxRecNum;

    /**
     * 获取单元格引用的表名和列信息
     * @param {string} cellString - 单元格字符串
     * @returns {Object} 包含tableName, columnName, bodyIndex, recNum, columnType的对象
     */
    function getCellRefTableNameAndColumnInfo(cellString) {
        var startPos = cellString.indexOf("[#");
        var endPos = cellString.indexOf("#]");
        var refStr = cellString.substring(startPos + 2, endPos);
        var parts = refStr.split(".");
        return {
            tableName: parts[0],
            columnName: parts[1],
            bodyIndex: parts[2],
            recNum: parts[3],
            columnType: parts[4]
        };
    }
};

/**
 * 复制并粘贴内容后填充
 * @param {number} reportCopy - 报表份数
 */
FillOneTemplate.prototype.CopyAndPasteContentThenFill = function (reportCopy) {
    if (reportCopy > 1) {
        var addRows = this.cell.GetRows(0) - 1 - this.printParam.coverLines;
        var copyContent = this.GetCopyContent1();

        for (var i = 0; i < reportCopy; i++) {
            var fillStartRow = 1;

            if (i === 0) {
                this.FillReportCopy(0, fillStartRow, this.printParam.reportBodyList);
                continue;
            }

            fillStartRow = this.cell.GetRows(0);
            this.cell.SetCopyContent(copyContent);
            this.InsertAndPasteContent();
            this.reportBodyAddRows += addRows;

            var reportBodyList = this.GetReportBodyList();
            this.FillReportCopy(i, fillStartRow, reportBodyList);
        }
    } else {
        var reportBodyList = this.GetReportBodyList();
        this.FillReportCopy(0, 1, reportBodyList);
    }
};

/**
 * 获取报表主体列表
 * @returns {Array} 报表主体列表
 */
FillOneTemplate.prototype.GetReportBodyList = function () {
    var reportBodyList = JSON.parse(JSON.stringify(this.printParam.reportBodyList));

    for (var i = 0; i < reportBodyList.length; i++) {
        reportBodyList[i].startRow += this.reportBodyAddRows;
        reportBodyList[i].endRow += this.reportBodyAddRows;
    }

    return reportBodyList;
};

/**
 * 填充报表副本
 * @param {number} copyNum - 副本编号
 * @param {number} fillStartRow - 填充起始行
 * @param {Array} reportBodyList - 报表主体列表
 */
FillOneTemplate.prototype.FillReportCopy = function (copyNum, fillStartRow, reportBodyList) {
    var fillOneReportCopy = new FillOneReportCopy(
        this.cell,
        this.rsAll,
        this.printParam,
        copyNum,
        fillStartRow,
        reportBodyList,
        this.totalRecordCount,
        this.fillReportSysInfo
    );
    this.fillOneTemplateOutInfo.pageNoColRowInfoList = this.fillOneTemplateOutInfo.pageNoColRowInfoList.concat(fillOneReportCopy.DoJob());
};

/**
 * 获取报表份数
 * @returns {number} 报表份数
 */
FillOneTemplate.prototype.GetReportCopy = function () {
    return Math.ceil((this.totalRecordCount - this.printParam.coverUseBodyRecordCount) / this.printParam.recordPerPage);
};

/**
 * 插入并粘贴内容
 */
FillOneTemplate.prototype.InsertAndPasteContent = function () {
    this.cell.InsertCleanRow(this.cell.GetRows(0), 1, 0);
    this.cell.mfPaste(1, this.cell.GetRows(0) - 1, 0, 1, 0);
};

/**
 * 获取复制内容
 * @returns {Object} 复制内容对象
 */
FillOneTemplate.prototype.GetCopyContent1 = function () {
    var copyStartRow = this.printParam.coverLines + 1;
    var copyEndRow = this.cell.GetRows(0) - 1;

    this.cell.mfCopyRange(1, copyStartRow, this.cell.GetCols(0) - 1, copyEndRow);

    return this.cell.GetCopyContent();
};

/**
 * 获取总记录数
 * @returns {number} 总记录数
 * @throws {Error} 当找不到对应表时抛出错误
 */
FillOneTemplate.prototype.GetTotalRecordCount = function () {
    var tableName = this.printParam.tablesUsedToRecordCount;
    var tableData = this.rsAll[tableName];
    if (tableData) {
        return tableData.length;
    }
    throw new Error("未找到模板参数中所定义的表" + this.printParam.tablesUsedToRecordCount + "的相关记录!");
};

'use strict';

/**
 * @fileoverview 合并报表主体列表内容模块 - 提供报表主体合并功能
 * @description 该模块负责合并多个报表主体的内容，
 * 支持横向和纵向两种合并方式。
 * @author MyCell Designer
 * @version 1.0.0
 */

/**
 * 合并报表主体列表内容类
 * @class MergeReportBodyListContent
 * @description 合并多个报表主体的内容
 * @param {Array} reportBodyList - 报表主体列表
 * @param {Object} cellSheet - 单元格表格对象
 * @returns {Object} 包含doJob方法的对象
 */
function MergeReportBodyListContent(reportBodyList, cellSheet) {
    /**
     * 执行合并任务
     * @function doJob
     * @description 根据报表主体的方向（横向/纵向）分别进行合并处理
     * @returns {void}
     */
    function doJob() {
        if (reportBodyList.length <= 1) {
            return reportBodyList;
        }
        var tAr = reportBodyList.filter(p => p.orientation == "横向");
        if (tAr.length > 1) {
            new MergeReportBodyListContentH(tAr, cellSheet).doJob();
        }
        tAr = reportBodyList.filter(p => p.orientation == "竖向");
        if (tAr.length > 1) {
            new MergeReportBodyListContentV(tAr, cellSheet).doJob();
        }
    }

    return {
        doJob: doJob
    }
}
'use strict';

/**
 * @fileoverview 合并报表主体列表内容（水平方向）模块
 * @description 用于合并水平方向上具有相同表头的报表主体，并调整记录编号
 * @module MergeReportBodyListContentH
 */

/**
 * 合并报表主体列表内容（水平方向）类
 * @class
 * @param {Array} reportBodyList - 报表主体列表
 * @param {Object} cellSheet - 单元格工作表
 */
function MergeReportBodyListContentH(reportBodyList, cellSheet) {
    var operCell = new OperCell();
    operCell.Open(cellSheet);

    function doJob() {
        if(readOnlyText){
            return;
        }
        var L = [];
        for (var i = 0; i < reportBodyList.length; i++) {
            var p = reportBodyList[i];
            var t1 = p.header;
            if (L.indexOf(t1) != -1) {
                continue;
            }
            L.push(t1);
            var tAr = getReportBodyHasSameHeader(t1);
            if (tAr.length > 1) {
                var L1 = mergeSameStartRowEndRowReportBodys(tAr);
                modifyRecNum(L1);
            }
        }
    }

    function mergeSameStartRowEndRowReportBodys(tAr) {
        var index = 0;
        var L = [];
        while (true) {
            var t1 = getOneSameStartRowEndRowReportBodys(tAr, index);
            if (t1) {
                L.push(t1);
            }
            else {
                L.push(tAr[index]);
            }
            index++;
            if (t1 && t1.reportBodyIndexList.indexOf(index) != -1) {
                index++;
            }
            if (index >= tAr.length - 1) {
                break;
            }
        }
        return L;
    }

    function getOneSameStartRowEndRowReportBodys(tAr, index) {
        var t1 = tAr[index];
        var tt = getSameStartRowEndRowReportBodys(t1, tAr, index + 1);
        if (tt) {
            var t2 = tt.reportBodyList[tt.reportBodyList.length - 1];
            var L1 = [index].concat(tt.reportBodyIndexList);
            return {
                reportBodyIndexList: L1,
                startCol: t1.startCol,
                startRow: t1.startRow,
                endCol: t2.endCol,
                endRow: t2.endRow
            }
        }
        return null;
    }

    function getSameStartRowEndRowReportBodys(t1, tAr, startIndex) {
        var L = [];
        var L1 = [];
        for (var i = startIndex; i < tAr.length; i++) {
            var t2 = tAr[i];
            if (t2.startRow == t1.startRow && t2.endRow == t1.endRow) {
                L.push(t2);
                L1.push(i);
            }
        }
        if (L.length > 0) {
            return {
                reportBodyList: L,
                reportBodyIndexList: L1
            };
        }
        return null;
    }

    function getReportBodyHasSameHeader(t1) {
        var L = [];
        for (var i = 0; i < reportBodyList.length; i++) {
            var p = reportBodyList[i];
            if (p.header == t1) {
                L.push(p);
            }
        }
        return L;
    }

    var addRecNum = 0;
    function modifyRecNum(L) {
        for (var i = 1; i < L.length; i++) {
            addRecNum = getMaxRecNum(L[i - 1]);
            if (addRecNum == -1) {
                break;
            }
            modifyRecNumOneReportBody(L[i]);
        }
    }

    function getMaxRecNum(o) {
        for (var row = o.endRow; row >= o.startRow; row--) {
            for (var col = o.endCol; col >= o.startCol; col--) {
                var t = getRealColRowObj(col, row);
                var s = cellSheet.cells[t.col][t.row].str;
                if (s.indexOf("[#") != -1 && s.indexOf("#]") != -1) {
                    var t1 = getCellRefTableNameAndColumnInfo(s);
                    return Number(t1.recNum);
                }
            }
        }
        return -1;
    }

    function getRealColRowObj(col1, row1) {
        var o = operCell.GetMergeRange(col1, row1);
        if (o != null && cellSheet.cells[col1 - 1][row1 - 1].isInMergeArea) {
            return {
                col: o.startCol - 1,
                row: o.startRow - 1
            }
        }
        else {
            return {
                col: col1 - 1,
                row: row1 - 1
            }
        }
    }

    function modifyRecNumOneReportBody(p) {
        for (var row = p.startRow - 1; row <= p.endRow - 1; row++) {
            for (var col = p.startCol - 1; col <= p.endCol - 1; col++) {
                var o = cellSheet.cells[col][row];
                var s = o.str;
                if (s.indexOf("[#") != -1 && s.indexOf("#]") != -1) {
                    modifyOneReportCell(s, col, row);
                }
            }
        }
    }

    function modifyOneReportCell(s, col, row) {        
        s = getAfterModifyValue(s);        
        cellSheet.cells[col][row].str = s;
    }

    function getAfterModifyValue(s) {
        var pos1 = s.indexOf("[#");
        var pos2 = s.indexOf("#]", pos1 + 1);
        while (pos1 != -1 && pos2 != -1) {
            var s1 = s.substring(pos1 - 2, pos2 + 2);
            var t1 = getCellRefTableNameAndColumnInfo(s1);
            var s2 = "[@" + t1.tableName + "." + t1.columnName + "." + t1.bodyIndex + "." + (Number(t1.recNum) + addRecNum) + "." + t1.columnType + "@]";
            s = s.replace(s1, s2);
            pos1 = s.indexOf("[#");
            if (pos1 == -1) {
                break;
            }
            pos2 = s.indexOf("#]", pos1 + 1);
        }
        s = s.replace(/\[@/g, "[#");
        s = s.replace(/\@]/g, "#]");
        return s;
    }

    function getCellRefTableNameAndColumnInfo(s) {
        var pos1 = s.indexOf("[#");
        var pos2 = s.indexOf("#]");
        var t1 = s.substring(pos1 + 2, pos2);
        var tAr = t1.split(".");
        var tableName = tAr[0];
        var columnName = tAr[1];
        var bodyIndex = tAr[2];
        var recNum = tAr[3];
        var columnType = tAr[4];
        return {
            tableName: tableName,
            columnName: columnName,
            bodyIndex: bodyIndex,
            recNum: recNum,
            columnType: columnType
        }
    }

    return {
        doJob: doJob
    }
}
'use strict';

/**
 * @fileoverview 合并报表主体列表内容（垂直方向）模块
 * @description 用于合并垂直方向上具有相同表头的报表主体，并调整记录编号
 * @module MergeReportBodyListContentV
 */

/**
 * 合并报表主体列表内容（垂直方向）类
 * @class
 * @param {Array} reportBodyList - 报表主体列表
 * @param {Object} cellSheet - 单元格工作表
 */
function MergeReportBodyListContentV(reportBodyList, cellSheet) {
    var operCell = new OperCell();
    operCell.Open(cellSheet);

    function doJob() {
        if(readOnlyText){
            return;
        }
        var L = [];
        for (var i = 0; i < reportBodyList.length; i++) {
            var p = reportBodyList[i];
            var t1 = p.header;
            if (L.indexOf(t1) != -1) {
                continue;
            }
            L.push(t1);
            var tAr = getReportBodyHasSameHeader(t1);
            if (tAr.length > 1) {
                var L1 = mergeSameStartColEndColReportBodys(tAr);
                modifyRecNum(L1);
            }
        }
    }

    function mergeSameStartColEndColReportBodys(tAr) {
        var index = 0;
        var L = [];
        while (true) {
            var t1 = getOneSameStartColEndColReportBodys(tAr, index);
            if (t1) {
                L.push(t1);
            }
            else {
                L.push(tAr[index]);
            }
            index++;
            if (t1 && t1.reportBodyIndexList.indexOf(index) != -1) {
                index++;
            }
            if (index >= tAr.length - 1) {
                break;
            }
        }
        return L;
    }

    function getOneSameStartColEndColReportBodys(tAr, index) {
        var t1 = tAr[index];
        var tt = getSameStartColEndColReportBodys(t1, tAr, index + 1);
        if (tt) {
            var t2 = tt.reportBodyList[tt.reportBodyList.length - 1];
            var L1 = [index].concat(tt.reportBodyIndexList);
            return {
                reportBodyIndexList: L1,
                startCol: t1.startCol,
                startRow: t1.startRow,
                endCol: t2.endCol,
                endRow: t2.endRow
            }
        }
        return null;
    }

    function getSameStartColEndColReportBodys(t1, tAr, startIndex) {
        var L = [];
        var L1 = [];
        for (var i = startIndex; i < tAr.length; i++) {
            var t2 = tAr[i];
            if (t2.startCol == t1.startCol && t2.endCol == t1.endCol) {
                L.push(t2);
                L1.push(i);
            }
        }
        if (L.length > 0) {
            return {
                reportBodyList: L,
                reportBodyIndexList: L1
            };
        }
        return null;
    }

    function getReportBodyHasSameHeader(t1) {
        var L = [];
        for (var i = 0; i < reportBodyList.length; i++) {
            var p = reportBodyList[i];
            if (p.header == t1) {
                L.push(p);
            }
        }
        return L;
    }

    var addRecNum = 0;
    function modifyRecNum(L) {
        for (var i = 1; i < L.length; i++) {
            addRecNum = getMaxRecNum(L[i - 1]);
            if (addRecNum == -1) {
                break;
            }
            modifyRecNumOneReportBody(L[i]);
        }
    }

    function getMaxRecNum(o) {
        for (var col = o.endCol; col >= o.startCol; col--) {
            for (var row = o.endRow; row >= o.startRow; row--) {
                var t = getRealColRowObj(col, row);
                var s = cellSheet.cells[t.col][t.row].str;
                if (s.indexOf("[#") != -1 && s.indexOf("#]") != -1) {
                    var t1 = getCellRefTableNameAndColumnInfo(s);
                    return Number(t1.recNum);
                }
            }
        }
        return -1;
    }

    function getRealColRowObj(col1, row1) {
        var o = operCell.GetMergeRange(col1, row1);
        if (o != null && cellSheet.cells[col1 - 1][row1 - 1].isInMergeArea) {
            return {
                col: o.startCol - 1,
                row: o.startRow - 1
            }
        }
        else {
            return {
                col: col1 - 1,
                row: row1 - 1
            }
        }
    }

    function modifyRecNumOneReportBody(p) {
        for (var row = p.startRow - 1; row <= p.endRow - 1; row++) {
            for (var col = p.startCol - 1; col <= p.endCol - 1; col++) {
                var o = cellSheet.cells[col][row];
                var s = o.str;
                if (s.indexOf("[#") != -1 && s.indexOf("#]") != -1) {
                    modifyOneReportCell(s, col, row);
                }
            }
        }
    }

    function modifyOneReportCell(s, col, row) {
        s = getAfterModifyValue(s);
        cellSheet.cells[col][row].str = s;
    }

    function getAfterModifyValue(s) {
        var pos1 = s.indexOf("[#");
        var pos2 = s.indexOf("#]", pos1 + 1);
        while (pos1 != -1 && pos2 != -1) {
            var s1 = s.substring(pos1 - 2, pos2 + 2);
            var t1 = getCellRefTableNameAndColumnInfo(s1);
            var s2 = "[@" + t1.tableName + "." + t1.columnName + "." + t1.bodyIndex + "." + (Number(t1.recNum) + addRecNum) + "." + t1.columnType + "@]";
            s = s.replace(s1, s2);
            pos1 = s.indexOf("[#");
            if (pos1 == -1) {
                break;
            }
            pos2 = s.indexOf("#]", pos1 + 1);
        }
        s = s.replace(/\[@/g, "[#");
        s = s.replace(/\@]/g, "#]");
        return s;
    }

    function getCellRefTableNameAndColumnInfo(s) {
        var pos1 = s.indexOf("[#");
        var pos2 = s.indexOf("#]");
        var t1 = s.substring(pos1 + 2, pos2);
        var tAr = t1.split(".");
        var tableName = tAr[0];
        var columnName = tAr[1];
        var bodyIndex = tAr[2];
        var recNum = tAr[3];
        var columnType = tAr[4];
        return {
            tableName: tableName,
            columnName: columnName,
            bodyIndex: bodyIndex,
            recNum: recNum,
            columnType: columnType
        }
    }

    return {
        doJob: doJob
    }
}
'use strict';

/**
 * @fileoverview 选择模板模块 - 提供报表模板选择功能
 * @description 该模块根据条件信息从多个模板中选择合适的模板，
 * 支持字符串、数值、日期类型的条件比较。
 * @author MyCell Designer
 * @version 1.0.0
 */

/**
 * 选择模板类
 * @class SelectTemplate
 * @description 根据条件选择合适的报表模板
 * @param {Object} rsAll - 所有结果集数据
 * @param {Array} reportTemplateConditionInfoList - 报表模板条件信息列表
 */
function SelectTemplate(rsAll, reportTemplateConditionInfoList) {
    this.rsAll = rsAll;
    this.reportTemplateConditionInfoList = reportTemplateConditionInfoList;
}

/**
 * 获取文件键列表
 * @function GetFileKeyList
 * @description 获取满足所有条件的模板文件键列表
 * @returns {Array.<string>} 文件键列表
 */
SelectTemplate.prototype.GetFileKeyList = function () {
    var fileKeyList = [];
    for (var i = 0; i < this.reportTemplateConditionInfoList.length; i++) {
        var conditionInfo = this.reportTemplateConditionInfoList[i];
        if (this.IsAllConditionSatisfied(conditionInfo)) {
            fileKeyList.push(conditionInfo.fileKey);
        }
    }
    return fileKeyList;
};

/**
 * 检查是否所有条件都满足
 * @function IsAllConditionSatisfied
 * @description 检查条件信息中的所有条件组是否至少有一个满足
 * @param {Object} conditionInfo - 条件信息对象
 * @returns {boolean} 是否满足条件
 */
SelectTemplate.prototype.IsAllConditionSatisfied = function (conditionInfo) {
    for (var i = 0; i < conditionInfo.reportTemplateConditionList.length; i++) {
        var conditionGroup = conditionInfo.reportTemplateConditionList[i];
        if (this.IsOneGroupConditionSatisfied(conditionGroup)) {
            return true;
        }
    }
    return false;
};

/**
 * 检查单个条件组是否满足
 * @function IsOneGroupConditionSatisfied
 * @description 检查单个条件组中的所有条件是否都满足
 * @param {Array} conditionGroup - 条件组数组
 * @returns {boolean} 是否满足所有条件
 */
SelectTemplate.prototype.IsOneGroupConditionSatisfied = function (conditionGroup) {
    for (var i = 0; i < conditionGroup.length; i++) {
        var condition = conditionGroup[i];
        if (!this.IsConditionEvalIsTrue(condition)) {
            return false;
        }
    }
    return true;
};

/**
 * 检查条件评估是否为真
 * @function IsConditionEvalIsTrue
 * @description 根据条件类型（字符、数值、日期）评估条件是否满足
 * @param {Object} condition - 条件对象
 * @returns {boolean} 条件是否满足
 */
SelectTemplate.prototype.IsConditionEvalIsTrue = function (condition) {
    var tAr = condition.columnName.split('.');
    var t = tAr[0];
    var c = tAr[1];
    var v = this.rsAll[t][0][c].toString();

    if (condition.columnType === "C") {
        return this.CompareString(v, condition);
    } else if (condition.columnType === "N") {
        return this.CompareNumber(v, condition);
    } else if (condition.columnType === "D") {
        return this.CompareDate(v, condition);
    } else {
        throw new Error("模板选择字段类型" + condition.columnType + "还未实现!");
    }
};

/**
 * 比较日期
 * @function CompareDate
 * @description 比较两个日期值
 * @param {string} v - 日期字符串值
 * @param {Object} condition - 条件对象，包含operation和value属性
 * @returns {boolean} 比较结果
 */
SelectTemplate.prototype.CompareDate = function (v, condition) {
    var d1 = Common.ParseDate(v);
    var d2 = Common.ParseDate(condition.value);
    var t = d1 - d2;

    if (condition.operation === "=") {
        return t === 0;
    } else if (condition.operation === "<>") {
        return t !== 0;
    } else if (condition.operation === "<") {
        return t < 0;
    } else if (condition.operation === "<=") {
        return t <= 0;
    } else if (condition.operation === ">") {
        return t > 0;
    } else if (condition.operation === ">=") {
        return t >= 0;
    } else {
        throw new Error("模板选择日期比较符" + condition.operation + "尚未实现!");
    }
};

/**
 * 比较字符串
 * @function CompareString
 * @description 比较两个字符串值
 * @param {string} v - 字符串值
 * @param {Object} condition - 条件对象，包含operation和value属性
 * @returns {boolean} 比较结果
 */
SelectTemplate.prototype.CompareString = function (v, condition) {
    if (condition.operation === "=") {
        return v === condition.value;
    } else if (condition.operation === "<>") {
        return v !== condition.value;
    } else if (condition.operation === "like") {
        return v.indexOf(condition.value) !== -1;
    } else {
        throw new Error("模板选择字符比较操作符" + condition.operation + "未实现!");
    }
};

/**
 * 比较数值
 * @function CompareNumber
 * @description 比较两个数值
 * @param {string} v - 数值字符串
 * @param {Object} condition - 条件对象，包含operation和value属性
 * @returns {boolean} 比较结果
 */
SelectTemplate.prototype.CompareNumber = function (v, condition) {
    if (condition.operation === "=") {
        return v === condition.value;
    } else if (condition.operation === "<>") {
        return v !== condition.value;
    } else {
        try {
            var t1 = parseFloat(v);
            var t2 = parseFloat(condition.value);

            if (condition.operation === "<") {
                return t1 < t2;
            } else if (condition.operation === "<=") {
                return t1 <= t2;
            } else if (condition.operation === ">") {
                return t1 > t2;
            } else if (condition.operation === ">=") {
                return t1 >= t2;
            }
        } catch (ex) {
            throw new Error("模板条件字段设置错误!字段值不能转换成数值类型!");
        }
    }
    throw new Error("模板选择数字比较操作符" + condition.operation + "未实现!");
};

/**
 * 创建选择模板实例（静态方法）
 * @function CreateSelectTemplate
 * @description 工厂方法，创建选择模板实例
 * @param {Object} rsAll - 所有结果集数据
 * @param {Array} reportTemplateConditionInfoList - 报表模板条件信息列表
 * @returns {SelectTemplate} 选择模板实例
 */
SelectTemplate.CreateSelectTemplate = function (rsAll, reportTemplateConditionInfoList) {
    return new SelectTemplate(rsAll, reportTemplateConditionInfoList);
};
/**
 * @fileoverview 开始执行模块 - 负责初始化报表生成流程
 * @description 该模块是报表生成的入口点，负责解析JSON数据、
 * 选择模板、合并报表主体、填充数据等整个报表生成流程的初始化。
 * @author MyCell Designer
 * @version 1.0.0
 */
'use strict';

/**
 * 开始执行类
 * @class StartDo
 * @description 负责初始化报表生成流程
 * @param {string} jsonStr - JSON数据字符串
 * @param {Array} reportTemplateList - 报表模板列表
 * @param {Array} reportTemplateConditionInfoList - 报表模板条件信息列表
 * @param {Array} reportTemplatePrintParamList - 报表模板打印参数列表
 * @param {Object} fillReportSysInfo - 填充报表系统信息
 */
function StartDo(jsonStr, reportTemplateList, reportTemplateConditionInfoList, reportTemplatePrintParamList, fillReportSysInfo) {
    /**
     * 所有结果集数据
     * @type {Object}
     */
    this.rsAll = JSON.parse(jsonStr);
    fillDataJsonData = this.rsAll;

    /**
     * 报表模板列表
     * @type {Array}
     */
    this.reportTemplateList = reportTemplateList;

    /**
     * 报表模板条件信息列表
     * @type {Array}
     */
    this.reportTemplateConditionInfoList = reportTemplateConditionInfoList;

    /**
     * 报表模板打印参数列表
     * @type {Array}
     */
    this.reportTemplatePrintParamList = reportTemplatePrintParamList;

    /**
     * 填充报表系统信息
     * @type {Object}
     */
    this.fillReportSysInfo = fillReportSysInfo;

    /**
     * 生成报表
     * @returns {Array} 填充模板输出信息列表
     */
    this.GenReport = function () {
        var fileKeyList = SelectTemplate.CreateSelectTemplate(this.rsAll, this.reportTemplateConditionInfoList).GetFileKeyList();

        if (fileKeyList.length === 0) {
            fileKeyList.push(this.reportTemplateList[0].fileKey);
        }

        var fillOneTemplateOutInfoList = [];

        for (var i = 0; i < fileKeyList.length; i++) {
            var fileKey = fileKeyList[i];
            var cellSheet = this.GetCellSheet(fileKey);
            var printParams = this.GetTemplatePrintParams(fileKey);
            new MergeReportBodyListContent(printParams.reportBodyList, cellSheet).doJob();
            var cell = new OperCell();
            cell.Open(cellSheet);
            var fillOneTemplateOutInfo = new FillOneTemplate(this.rsAll, cell, printParams, this.fillReportSysInfo).DoJob();
            fillOneTemplateOutInfo.cell = cell;
            fillOneTemplateOutInfo.cellSheet = cellSheet;
            fillOneTemplateOutInfoList.push(fillOneTemplateOutInfo);
        }

        return fillOneTemplateOutInfoList;
    };

    /**
     * 获取模板打印参数
     * @param {string} fileKey - 文件键
     * @returns {Object} 打印参数对象
     * @throws {Error} 当找不到对应模板参数时抛出错误
     */
    this.GetTemplatePrintParams = function (fileKey) {
        for (var i = 0; i < this.reportTemplatePrintParamList.length; i++) {
            var param = this.reportTemplatePrintParamList[i];
            if (param.fileKey === fileKey) {
                return param;
            }
        }
        throw new Error("未找到" + fileKey + "对应的模板参数!");
    };

    /**
     * 获取单元格工作表
     * @param {string} fileKey - 文件键
     * @returns {Object} 单元格工作表对象
     * @throws {Error} 当找不到对应模板时抛出错误
     */
    this.GetCellSheet = function (fileKey) {
        for (var i = 0; i < this.reportTemplateList.length; i++) {
            var template = this.reportTemplateList[i];
            if (template.fileKey === fileKey) {
                return JSON.parse(template.jsonStr);
            }
        }
        throw new Error("未找到" + fileKey + "对应的模板!");
    };
}

/**
 * 创建开始执行实例的静态方法
 * @param {string} jsonStr - JSON数据字符串
 * @param {Array} reportTemplateList - 报表模板列表
 * @param {Array} reportTemplateConditionInfoList - 报表模板条件信息列表
 * @param {Array} reportTemplatePrintParamList - 报表模板打印参数列表
 * @param {Object} fillReportSysInfo - 填充报表系统信息
 * @returns {StartDo} 开始执行实例
 */
StartDo.CreateStartDo = function (jsonStr, reportTemplateList, reportTemplateConditionInfoList, reportTemplatePrintParamList, fillReportSysInfo) {
    return new StartDo(jsonStr, reportTemplateList, reportTemplateConditionInfoList, reportTemplatePrintParamList, fillReportSysInfo);
};

