    var index = operCell.AddImage(base64, imageType);
    operCell.SetCellImage(t.col, t.row, 0, index, 3, 2, 2);
    drawObjTypes.push(DrawObjType.cellImage);
    redraw({ isNeedRedrawMark: true });
